import React, { useState } from 'react';
import { FamilyMember } from '../types';

interface MemberNodeProps {
  member: FamilyMember;
  isAdmin: boolean;
  onEdit?: (member: FamilyMember) => void;
  onAddChild?: (parentId: string) => void;
}

const MemberNode: React.FC<MemberNodeProps> = ({ member, isAdmin, onEdit, onAddChild }) => {
  const [isExpanded, setIsExpanded] = useState(true);
  const hasChildren = member.children && member.children.length > 0;

  const toggleExpand = () => {
    setIsExpanded(!isExpanded);
  };

  return (
    <div className="flex flex-col items-center transition-all duration-500">
      {/* Member Card */}
      <div className="relative group">
        <div className={`
          p-4 rounded-lg border-2 shadow-md w-52 text-center relative z-10
          transition-all duration-300 transform group-hover:scale-105
          ${member.isMale ? 'bg-blue-50 border-blue-300' : 'bg-pink-50 border-pink-300'}
        `}>
          {isAdmin && (
            <div className="absolute -top-2 -right-2 flex gap-1 z-30">
              <button 
                onClick={() => onEdit?.(member)}
                className="bg-yellow-500 text-white p-1 rounded-full hover:bg-yellow-600 shadow-sm"
                title="Sửa thông tin"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                </svg>
              </button>
              <button 
                onClick={() => onAddChild?.(member.id)}
                className="bg-green-600 text-white p-1 rounded-full hover:bg-green-700 shadow-sm"
                title="Thêm con"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          )}

          <div className="font-bold text-red-900 text-lg font-traditional">{member.name}</div>
          <div className="text-xs text-gray-500 italic mb-1 uppercase tracking-tighter">Đời thứ {member.generation}</div>
          {member.birthDate && <div className="text-xs text-gray-600">*{member.birthDate}</div>}

          {member.bio && (
            <div className="mt-2 text-[10px] text-gray-400 border-t border-gray-200 pt-1 line-clamp-1">
              {member.bio}
            </div>
          )}
        </div>

        {/* Expansion Toggle Button */}
        {hasChildren && (
          <button
            onClick={toggleExpand}
            className={`
              absolute left-1/2 -bottom-4 -translate-x-1/2 z-20
              w-8 h-8 rounded-full border-2 border-gold shadow-lg
              flex items-center justify-center transition-all duration-300
              ${isExpanded ? 'bg-red-800 text-gold' : 'bg-gold text-red-900'}
              hover:scale-110 active:scale-95
            `}
            title={isExpanded ? "Thu gọn" : "Mở rộng"}
          >
            {isExpanded ? (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" />
              </svg>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" />
              </svg>
            )}
          </button>
        )}
      </div>

      {/* Recursive Children Rendering */}
      {hasChildren && isExpanded && (
        <div className="relative mt-12 transition-all duration-500 animate-fadeIn">
          <div className="absolute top-[-48px] left-1/2 w-0.5 h-12 bg-gold -translate-x-1/2" />

          <div className="flex gap-12 justify-center relative">
            {member.children!.length > 1 && (
              <div 
                className="absolute top-0 left-1/2 h-0.5 bg-gold -translate-x-1/2" 
                style={{ 
                  width: `calc(100% - ${100/member.children!.length}%)` 
                }} 
              />
            )}

            {member.children!.map((child) => (
              <div key={child.id} className="relative pt-6">
                <div className="absolute top-0 left-1/2 w-0.5 h-6 bg-gold -translate-x-1/2" />
                <MemberNode member={child} isAdmin={isAdmin} onEdit={onEdit} onAddChild={onAddChild} />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const FamilyTree: React.FC<{ root: FamilyMember; isAdmin?: boolean; onEditMember?: (m: FamilyMember) => void; onAddChild?: (parentId: string) => void }> = ({ root, isAdmin = false, onEditMember, onAddChild }) => {
