    <div className="bg-white/60 backdrop-blur-sm rounded-2xl border-2 border-gold/40 shadow-inner p-4">
      <div className="text-center mb-10">
        <h3 className="text-2xl font-traditional text-red-900 italic">Sơ đồ phả hệ (Phả đồ)</h3>
