      </div>

      <div className="overflow-x-auto overflow-y-hidden pb-20 pt-10">
        <div className="inline-block min-w-full text-center">
          <MemberNode member={root} isAdmin={isAdmin} onEdit={onEditMember} onAddChild={onAddChild} />
        </div>
      </div>
    </div>
  );
};

