      <header className="relative w-full h-[300px] md:h-[500px] flex flex-col items-center justify-center bg-cover bg-center shadow-2xl border-b-8 border-gold overflow-hidden">
        <div className="absolute inset-0 bg-black/20 pointer-events-none"></div>

        <img 
          src={bannerUrl} 
          alt="Clan Banner" 
          className="absolute inset-0 w-full h-full object-cover transition-all duration-700"
