                  className="w-full border-2 border-gray-200 rounded-lg px-4 py-2 focus:border-red-600 outline-none"
                  placeholder="Nhập mật khẩu quản trị..."
                  autoFocus
                />
              </div>
              <div className="flex gap-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg hover:bg-red-900 shadow-lg">Đăng nhập</button>
                <button type="button" onClick={() => setShowLogin(false)} className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-lg hover:bg-gray-200">Hủy</button>
              </div>
              <p className="text-center text-xs text-gray-400 mt-4">Gợi ý: admin123</p>
            </form>
          </div>
        </div>
      )}

      {/* Edit Member Modal */}
      {editingMember && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Sửa thông tin thành viên</h3>
            <form onSubmit={saveMember} className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Họ và Tên</label>
                <input 
                  type="text" 
                  value={editingMember.name}
