                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Giới tính</label>
                  <select 
                    value={editingMember.isMale ? 'male' : 'female'}
                    onChange={(e) => setEditingMember({...editingMember, isMale: e.target.value === 'male'})}
                    className="w-full border-2 border-gray-200 rounded-lg px-4 py-2"
                  >
                    <option value="male">Nam</option>
                    <option value="female">Nữ</option>
