                <label className="block text-sm font-bold text-gray-700 mb-1">Tiểu sử ngắn</label>
                <textarea 
                  value={editingMember.bio || ''}
                  onChange={(e) => setEditingMember({...editingMember, bio: e.target.value})}
                  className="w-full border-2 border-gray-200 rounded-lg px-4 py-2 h-24"
                />
              </div>
              <div className="flex gap-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg hover:bg-red-900 shadow-lg">Lưu thay đổi</button>
