      {/* Edit News Modal */}
      {editingNews && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Biên tập tin tức</h3>
