                    className="w-full border-2 border-gray-200 rounded-lg px-4 py-2"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Tóm tắt ngắn</label>
                <textarea 
                  value={editingNews.summary}
                  onChange={(e) => setEditingNews({...editingNews, summary: e.target.value})}
                  className="w-full border-2 border-gray-200 rounded-lg px-4 py-2 h-20"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Nội dung chi tiết</label>
                <textarea 
                  value={editingNews.content}
                  onChange={(e) => setEditingNews({...editingNews, content: e.target.value})}
                  className="w-full border-2 border-gray-200 rounded-lg px-4 py-2 h-40"
                  required
                />
              </div>
              <div className="flex gap-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg hover:bg-red-900 shadow-lg">Lưu bài viết</button>
                <button type="button" onClick={() => setEditingNews(null)} className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-lg hover:bg-gray-200">Hủy</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="mt-20 py-10 bg-[#1a0000] text-yellow-100 border-t-8 border-gold">
        <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
          <div>
            <h4 className="text-xl font-traditional mb-4 uppercase tracking-wider text-gold">Cổng Thông Tin Dòng Họ</h4>
            <p className="opacity-80">Lưu giữ truyền thống - Kết nối tương lai</p>
            <p className="mt-4">Địa chỉ liên hệ: {address}</p>
            {!isAdmin && (
              <button 
                onClick={() => setShowLogin(true)}
                className="mt-6 text-xs text-gold/50 hover:text-gold transition-colors flex items-center gap-1"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" />
                </svg>
                Quản trị viên đăng nhập
              </button>
            )}
          </div>
          <div className="text-center md:text-right italic text-gold/80">
            "Tổ Tông Công Đức Thiên Niên Thịnh<br/>Tử Hiếu Tôn Hiền Vạn Đại Vinh"
          </div>
