        <div className="text-center mt-10 text-xs opacity-50 border-t border-gold/20 pt-6">
          &copy; 2024 Hệ Thống Quản Lý Gia Phả Truyền Thống.
        </div>
      </footer>
    </div>
  );
};

export default App;

