  regulations: string[];
}

import React, { useState } from 'react';
import { FamilyMember } from '../types';

interface MemberNodeProps {
  member: FamilyMember;
  isAdmin: boolean;
  onEdit?: (member: FamilyMember) => void;
  onAddChild?: (parentId: string) => void;
}

const MemberNode: React.FC<MemberNodeProps> = ({ member, isAdmin, onEdit, onAddChild }) => {
  const [isExpanded, setIsExpanded] = useState(true);
  const hasChildren = member.children && member.children.length > 0;

  const toggleExpand = () => {
    setIsExpanded(!isExpanded);
  };

  return (
    <div className="flex flex-col items-center transition-all duration-500">
      {/* Member Card + Spouse Container */}
      <div className="relative group flex items-center justify-center gap-2">
        {/* Main Member Card */}
        <div className={`
          p-3 rounded-lg border-2 shadow-md w-44 text-center relative z-10
          transition-all duration-300 transform group-hover:shadow-xl
          ${member.isMale ? 'bg-blue-50 border-blue-300' : 'bg-pink-50 border-pink-300'}
        `}>
          {isAdmin && (
            <div className="absolute -top-3 -left-3 flex gap-1 z-30">
              <button 
                onClick={() => onEdit?.(member)}
                className="bg-yellow-500 text-white p-1.5 rounded-full hover:bg-yellow-600 shadow-md border border-white"
                title="Sửa thông tin"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                </svg>
              </button>
            </div>
          )}

          <div className="font-bold text-red-900 text-base font-traditional truncate">{member.name}</div>
          <div className="text-[10px] text-gray-500 italic mb-1 uppercase">Đời {member.generation}</div>
          {member.birthDate && <div className="text-[10px] text-gray-600">*{member.birthDate}</div>}
        </div>

        {/* Spouse Card */}
        {member.spouseName && (
          <div className={`
            p-3 rounded-lg border-2 border-dashed shadow-sm w-44 text-center relative z-10
            ${!member.isMale ? 'bg-blue-50 border-blue-200' : 'bg-pink-50 border-pink-200'}
          `}>
             <div className="font-bold text-red-800 text-base font-traditional truncate">{member.spouseName}</div>
             <div className="text-[10px] text-gray-400 italic">Vợ/Chồng</div>
          </div>
        )}

        {/* Connection Link between Member and Spouse */}
        {member.spouseName && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-8 h-0.5 bg-gray-300 -z-0"></div>
        )}

        {/* Admin Add Child Button */}
        {isAdmin && (
          <button 
            onClick={() => onAddChild?.(member.id)}
            className="absolute -right-4 top-1/2 -translate-y-1/2 bg-green-600 text-white p-1 rounded-full hover:bg-green-700 shadow-sm z-30 opacity-0 group-hover:opacity-100 transition-opacity"
            title="Thêm con"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" />
            </svg>
          </button>
        )}

        {/* Expansion Toggle Button */}
        {hasChildren && (
          <button
            onClick={toggleExpand}
            className={`
              absolute left-1/2 -bottom-4 -translate-x-1/2 z-20
              w-7 h-7 rounded-full border-2 border-gold shadow-md
              flex items-center justify-center transition-all duration-300
              ${isExpanded ? 'bg-red-800 text-gold' : 'bg-gold text-red-900'}
              hover:scale-110
            `}
          >
            {isExpanded ? (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" />
              </svg>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" />
              </svg>
            )}
          </button>
        )}
      </div>

      {/* Children Lines & Nodes */}
      {hasChildren && isExpanded && (
        <div className="relative mt-12">
          {/* Vertical line from parent center */}
          <div className="absolute top-[-48px] left-1/2 w-0.5 h-12 bg-gold/60 -translate-x-1/2" />

          <div className="flex gap-16 justify-center relative px-8">
            {member.children!.length > 1 && (
              <div 
                className="absolute top-0 left-0 right-0 h-0.5 bg-gold/60 mx-auto" 
                style={{ 
                  width: `calc(100% - ${100/member.children!.length}%)` 
                }} 
              />
            )}

            {member.children!.map((child) => (
              <div key={child.id} className="relative pt-6 flex flex-col items-center">
                {/* Short vertical line to child */}
                <div className="absolute top-0 left-1/2 w-0.5 h-6 bg-gold/60 -translate-x-1/2" />
                <MemberNode member={child} isAdmin={isAdmin} onEdit={onEdit} onAddChild={onAddChild} />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const FamilyTree: React.FC<{ 
  root: FamilyMember; 
  isAdmin?: boolean; 
  onEditMember?: (m: FamilyMember) => void; 
  onAddChild?: (parentId: string) => void 
}> = ({ root, isAdmin = false, onEditMember, onAddChild }) => {
  return (
    <div className="bg-white/40 backdrop-blur-md rounded-2xl border-2 border-gold/30 shadow-inner p-8 overflow-hidden">
      <div className="text-center mb-16">
        <h3 className="text-3xl font-traditional text-red-900 italic mb-2">Phả Đồ Dòng Họ</h3>
        <p className="text-sm text-gray-600">Sơ đồ kết nối các thế hệ, bấm +/- để xem chi tiết các chi phái</p>
      </div>

      <div className="overflow-x-auto overflow-y-auto min-h-[600px] pb-32 flex justify-center">
        <div className="inline-block p-10">
          <MemberNode member={root} isAdmin={isAdmin} onEdit={onEditMember} onAddChild={onAddChild} />
        </div>
      </div>
    </div>
  );
};

export default FamilyTree;

import React, { useState, useEffect } from 'react';
import { AppSection, FamilyMember, NewsItem } from './types';
import Navigation from './components/Navigation';
import FamilyTree from './components/FamilyTree';
import { 
  CLAN_NAME, CLAN_ADDRESS, SAMPLE_NEWS, SAMPLE_FAMILY_TREE 
} from './constants';
import { generateClanHistory } from './services/geminiService';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.NEWS);

  // Content States
  const [news, setNews] = useState<NewsItem[]>(() => {
    const saved = localStorage.getItem('clan_news');
    return saved ? JSON.parse(saved) : SAMPLE_NEWS;
  });
  const [familyTree, setFamilyTree] = useState<FamilyMember>(() => {
    const saved = localStorage.getItem('clan_tree');
    return saved ? JSON.parse(saved) : SAMPLE_FAMILY_TREE;
  });
  const [bannerUrl, setBannerUrl] = useState<string>(() => {
    return localStorage.getItem('clan_banner') || "https://raw.githubusercontent.com/stackblitz/stackblitz-images/main/clan-banner-bg.jpg";
  });
  const [address, setAddress] = useState<string>(() => {
    return localStorage.getItem('clan_address') || CLAN_ADDRESS;
  });
  const [historyText, setHistoryText] = useState<string>(() => {
    return localStorage.getItem('clan_history') || "Lịch sử dòng họ đang được cập nhật...";
  });
  const [ancestralHouseText, setAncestralHouseText] = useState<string>(() => {
    return localStorage.getItem('clan_house_text') || "Từ đường là nơi thờ tự linh thiêng, nơi lưu giữ hồn cốt của tổ tiên qua bao thế hệ. Ngôi từ đường được xây dựng trang nghiêm, là điểm tựa tâm linh cho con cháu muôn đời.";
  });
  const [regulations, setRegulations] = useState<string[]>(() => {
    const saved = localStorage.getItem('clan_regulations');
    return saved ? JSON.parse(saved) : [
      "Luôn giữ gìn và phát huy truyền thống tốt đẹp của dòng họ, tôn trọng các bậc tiền bối, yêu thương đùm bọc con cháu.",
      "Khuyến khích con cháu thi đua học tập, lao động sản xuất, đóng góp công sức xây dựng quê hương, dòng họ ngày càng giàu đẹp.",
      "Thực hiện tốt nghĩa vụ công dân, chấp hành pháp luật của Nhà nước và các quy định của địa phương.",
      "Tham gia đầy đủ các hoạt động của dòng họ, đặc biệt là các ngày giỗ tổ, chạp họ hàng năm.",
      "Giữ gìn sự đoàn kết nội bộ, giải quyết các mâu thuẫn trên tinh thần hòa giải, trọng tình trọng nghĩa."
    ];
  });

  // Admin states
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [password, setPassword] = useState('');
  const [editingMember, setEditingMember] = useState<FamilyMember | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);
  const [isEditingText, setIsEditingText] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('clan_news', JSON.stringify(news));
    localStorage.setItem('clan_tree', JSON.stringify(familyTree));
    localStorage.setItem('clan_banner', bannerUrl);
    localStorage.setItem('clan_address', address);
    localStorage.setItem('clan_history', historyText);
    localStorage.setItem('clan_house_text', ancestralHouseText);
    localStorage.setItem('clan_regulations', JSON.stringify(regulations));
  }, [news, familyTree, bannerUrl, address, historyText, ancestralHouseText, regulations]);

  // Initial History generation if empty
  useEffect(() => {
    if (historyText === "Lịch sử dòng họ đang được cập nhật...") {
      const fetchHistory = async () => {
        const data = await generateClanHistory(CLAN_NAME, address);
        if (data) setHistoryText(data);
      };
      fetchHistory();
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') {
      setIsAdmin(true);
      setShowLogin(false);
      setPassword('');
    } else {
      alert('Sai mật khẩu! (Gợi ý: admin123)');
    }
  };

  const saveNews = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingNews) return;
    if (news.find(n => n.id === editingNews.id)) {
      setNews(news.map(n => n.id === editingNews.id ? editingNews : n));
    } else {
      setNews([editingNews, ...news]);
    }
    setEditingNews(null);
  };

  const saveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingMember) return;
    const updateNode = (node: FamilyMember): FamilyMember => {
      if (node.id === editingMember.id) return editingMember;
      if (node.children) {
        return { ...node, children: node.children.map(updateNode) };
      }
      return node;
    };
    setFamilyTree(updateNode(familyTree));
    setEditingMember(null);
  };

  const addChild = (parentId: string) => {
    const newId = `child-${Date.now()}`;
    const newChild: FamilyMember = {
      id: newId,
      name: 'Tên thành viên mới',
      generation: 0,
      isMale: true,
      spouseName: ''
    };

    const addNode = (node: FamilyMember): FamilyMember => {
      if (node.id === parentId) {
        const updatedChild = { ...newChild, generation: node.generation + 1 };
        return { ...node, children: [...(node.children || []), updatedChild] };
      }
      if (node.children) return { ...node, children: node.children.map(addNode) };
      return node;
    };
    setFamilyTree(addNode(familyTree));
  };

  const renderSection = () => {
    switch (activeSection) {
      case AppSection.NEWS:
        return (
          <div className="animate-fadeIn">
            {isAdmin && (
              <div className="mb-8 flex justify-center">
                <button onClick={() => setEditingNews({ id: Date.now().toString(), title: '', date: new Date().toLocaleDateString('vi-VN'), summary: '', content: '', imageUrl: 'https://picsum.photos/800/400' })} className="bg-green-700 text-white px-6 py-2 rounded-full font-bold shadow-lg hover:bg-green-800 transition-colors flex items-center gap-2">Thêm Tin Tức</button>
              </div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {news.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-lg overflow-hidden border border-gold/20 relative group">
                  {isAdmin && (
                    <div className="absolute top-2 right-2 flex gap-2 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => setEditingNews(item)} className="bg-yellow-500 text-white p-2 rounded-full shadow hover:bg-yellow-600">Sửa</button>
                      <button onClick={() => setNews(news.filter(n => n.id !== item.id))} className="bg-red-600 text-white p-2 rounded-full shadow hover:bg-red-700">Xóa</button>
                    </div>
                  )}
                  <img src={item.imageUrl} alt={item.title} className="w-full h-48 object-cover" />
                  <div className="p-6">
                    <span className="text-xs font-bold text-red-600 uppercase tracking-widest">{item.date}</span>
                    <h3 className="text-xl font-bold text-red-900 mt-2 mb-3">{item.title}</h3>
                    <p className="text-gray-600 text-sm line-clamp-3">{item.summary}</p>
                    <button className="mt-4 text-red-800 font-bold hover:underline">Xem chi tiết →</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case AppSection.TREE:
        return <FamilyTree root={familyTree} isAdmin={isAdmin} onEditMember={setEditingMember} onAddChild={addChild} />;
      case AppSection.CHRONICLES:
        return (
          <div className="prose prose-lg max-w-none bg-white p-10 rounded-xl shadow-lg border-2 border-double border-gold animate-fadeIn">
            <div className="flex justify-between items-center border-b-2 border-gold pb-4 mb-6">
               <h2 className="text-3xl font-traditional text-red-900 italic m-0">Phả Kỹ Dòng Họ</h2>
               {isAdmin && (
                 <button onClick={() => setIsEditingText(!isEditingText)} className="bg-red-800 text-white px-4 py-1 rounded text-sm uppercase">
                   {isEditingText ? "Xong" : "Chỉnh sửa"}
                 </button>
               )}
            </div>
            {isEditingText && isAdmin ? (
              <textarea 
                value={historyText} 
                onChange={(e) => setHistoryText(e.target.value)}
                className="w-full h-96 p-4 border rounded font-sans text-base leading-relaxed"
              />
            ) : (
              <div className="whitespace-pre-wrap leading-relaxed text-gray-800 font-medium">
                {historyText}
              </div>
            )}
          </div>
        );
      case AppSection.ANCESTRAL_HOUSE:
        return (
          <div className="bg-white p-8 rounded-xl shadow-lg border border-gold animate-fadeIn">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-3xl font-traditional text-red-900 m-0">Từ Đường Dòng Họ</h2>
              {isAdmin && (
                <button onClick={() => setIsEditingText(!isEditingText)} className="bg-red-800 text-white px-4 py-1 rounded text-sm uppercase">
                  {isEditingText ? "Xong" : "Sửa mô tả"}
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <p className="text-lg"><strong>Địa chỉ:</strong> {address}</p>
                {isEditingText && isAdmin ? (
                  <textarea 
                    value={ancestralHouseText} 
                    onChange={(e) => setAncestralHouseText(e.target.value)}
                    className="w-full h-40 p-4 border rounded"
                  />
                ) : (
                  <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{ancestralHouseText}</p>
                )}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <img src="https://picsum.photos/seed/house1/400/300" alt="Từ đường 1" className="rounded-lg shadow" />
                <img src="https://picsum.photos/seed/house2/400/300" alt="Từ đường 2" className="rounded-lg shadow" />
                <img src="https://picsum.photos/seed/house3/400/300" alt="Từ đường 3" className="rounded-lg shadow" />
                <img src="https://picsum.photos/seed/house4/400/300" alt="Từ đường 4" className="rounded-lg shadow" />
              </div>
            </div>
          </div>
        );
      case AppSection.REGULATIONS:
        return (
          <div className="max-w-4xl mx-auto bg-[#fffdf0] p-12 shadow-2xl rounded-sm border-[16px] border-double border-red-900 relative animate-fadeIn">
             <div className="flex justify-between items-center mb-10">
               <div className="w-10"></div>
               <h2 className="text-4xl font-traditional text-red-900 m-0 uppercase tracking-widest">Tộc Ước Dòng Họ</h2>
               {isAdmin ? (
                  <button onClick={() => setIsEditingText(!isEditingText)} className="bg-red-800 text-white px-4 py-1 rounded text-xs uppercase">
                    {isEditingText ? "Xong" : "Sửa tộc ước"}
                  </button>
               ) : <div className="w-10"></div>}
             </div>

             {isEditingText && isAdmin ? (
               <textarea 
                 value={regulations.join('\n')}
                 onChange={(e) => setRegulations(e.target.value.split('\n'))}
                 className="w-full h-64 p-4 border-2 border-gold/50 bg-white"
                 placeholder="Nhập mỗi điều một dòng..."
               />
             ) : (
               <div className="space-y-6 text-lg text-red-950 italic">
                 {regulations.filter(r => r.trim()).map((reg, idx) => (
                   <p key={idx}><strong>Điều {idx + 1}:</strong> {reg}</p>
                 ))}
               </div>
             )}
             <div className="mt-12 text-center text-sm text-red-800">- Trích lục từ bản gốc lưu tại Từ Đường -</div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="relative w-full h-[300px] md:h-[500px] flex items-center justify-center bg-cover bg-center shadow-2xl border-b-8 border-gold overflow-hidden">
        <img src={bannerUrl} alt="Banner" className="absolute inset-0 w-full h-full object-cover" />
        {isAdmin && <button onClick={() => { const url = prompt('URL ảnh bìa:', bannerUrl); if(url) setBannerUrl(url); }} className="absolute top-4 right-4 bg-black/60 text-white px-4 py-2 rounded z-20">Thay ảnh bìa</button>}
        <div className="absolute bottom-6 w-full text-center z-10">
          <div className="inline-block bg-black/40 backdrop-blur-sm px-6 py-2 rounded-full border border-gold/50 shadow-lg">
            <p className="text-white font-medium" onClick={isAdmin ? () => { const a = prompt('Địa chỉ:', address); if(a) setAddress(a); } : undefined}>
              Địa chỉ: <span className="text-gold font-bold">{address}</span>
            </p>
          </div>
        </div>
      </header>

      {isAdmin && (
        <div className="bg-red-800 text-gold text-center py-2 font-bold uppercase text-xs flex justify-center items-center gap-4">
          <span>● CHẾ ĐỘ QUẢN TRỊ VIÊN</span>
          <button onClick={() => setIsAdmin(false)} className="underline">Thoát</button>
        </div>
      )}

      <div className="max-w-7xl mx-auto px-4 mt-[-40px] relative z-20">
        <Navigation activeSection={activeSection} onSectionChange={(s) => { setActiveSection(s); setIsEditingText(false); }} />
        <main className="mt-8">{renderSection()}</main>
      </div>

      {showLogin && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Đăng nhập Quản trị</h3>
            <form onSubmit={handleLogin} className="space-y-4">
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full border-2 rounded-lg px-4 py-2" placeholder="Mật khẩu..." autoFocus />
              <div className="flex gap-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg">Đăng nhập</button>
                <button type="button" onClick={() => setShowLogin(false)} className="flex-1 bg-gray-100 py-3 rounded-lg">Hủy</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {editingMember && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Biên tập thành viên</h3>
            <form onSubmit={saveMember} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700">Họ và Tên</label>
                  <input type="text" value={editingMember.name} onChange={(e) => setEditingMember({...editingMember, name: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700">Vợ / Chồng</label>
                  <input type="text" value={editingMember.spouseName || ''} onChange={(e) => setEditingMember({...editingMember, spouseName: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2" placeholder="Tên vợ hoặc chồng..." />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700">Giới tính</label>
                  <select value={editingMember.isMale ? 'male' : 'female'} onChange={(e) => setEditingMember({...editingMember, isMale: e.target.value === 'male'})} className="w-full border-2 rounded-lg px-4 py-2">
                    <option value="male">Nam</option>
                    <option value="female">Nữ</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700">Năm sinh</label>
                  <input type="text" value={editingMember.birthDate || ''} onChange={(e) => setEditingMember({...editingMember, birthDate: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700">Tiểu sử</label>
                <textarea value={editingMember.bio || ''} onChange={(e) => setEditingMember({...editingMember, bio: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 h-20" />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg shadow-lg">Lưu lại</button>
                <button type="button" onClick={() => setEditingMember(null)} className="flex-1 bg-gray-100 py-3 rounded-lg">Đóng</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {editingNews && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Biên tập tin tức</h3>
            <form onSubmit={saveNews} className="space-y-4">
              <input type="text" value={editingNews.title} onChange={(e) => setEditingNews({...editingNews, title: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2" placeholder="Tiêu đề..." required />
              <textarea value={editingNews.summary} onChange={(e) => setEditingNews({...editingNews, summary: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 h-20" placeholder="Tóm tắt..." required />
              <textarea value={editingNews.content} onChange={(e) => setEditingNews({...editingNews, content: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 h-40" placeholder="Nội dung..." required />
              <div className="flex gap-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg">Lưu bài viết</button>
                <button type="button" onClick={() => setEditingNews(null)} className="flex-1 bg-gray-100 py-3 rounded-lg">Hủy</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <footer className="mt-20 py-10 bg-[#1a0000] text-yellow-100 border-t-8 border-gold">
        <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
          <div>
            <h4 className="text-xl font-traditional mb-4 uppercase text-gold">Cổng Thông Tin Dòng Họ</h4>
            <p className="mt-4">Địa chỉ liên hệ: {address}</p>
            {!isAdmin && <button onClick={() => setShowLogin(true)} className="mt-6 text-xs text-gold/50 flex items-center gap-1">Quản trị đăng nhập</button>}
          </div>
          <div className="text-center md:text-right italic text-gold/80">"Tổ Tông Công Đức Thiên Niên Thịnh<br/>Tử Hiếu Tôn Hiền Vạn Đại Vinh"</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppSection, FamilyMember, NewsItem } from './types';
import Navigation from './components/Navigation';
import FamilyTree from './components/FamilyTree';
import { 
  CLAN_NAME, CLAN_ADDRESS, SAMPLE_NEWS, SAMPLE_FAMILY_TREE 
} from './constants';
import { generateClanHistory } from './services/geminiService';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.NEWS);
  const bannerInputRef = useRef<HTMLInputElement>(null);

  // Content States with LocalStorage Persistence
  const [news, setNews] = useState<NewsItem[]>(() => {
    const saved = localStorage.getItem('clan_news');
    return saved ? JSON.parse(saved) : SAMPLE_NEWS;
  });
  const [familyTree, setFamilyTree] = useState<FamilyMember>(() => {
    const saved = localStorage.getItem('clan_tree');
    return saved ? JSON.parse(saved) : SAMPLE_FAMILY_TREE;
  });
  const [bannerUrl, setBannerUrl] = useState<string>(() => {
    return localStorage.getItem('clan_banner') || "https://raw.githubusercontent.com/stackblitz/stackblitz-images/main/clan-banner-bg.jpg";
  });
  const [address, setAddress] = useState<string>(() => {
    return localStorage.getItem('clan_address') || CLAN_ADDRESS;
  });
  const [historyText, setHistoryText] = useState<string>(() => {
    return localStorage.getItem('clan_history') || "Lịch sử dòng họ đang được cập nhật...";
  });
  const [ancestralHouseText, setAncestralHouseText] = useState<string>(() => {
    return localStorage.getItem('clan_house_text') || "Từ đường là nơi thờ tự linh thiêng, nơi lưu giữ hồn cốt của tổ tiên qua bao thế hệ. Ngôi từ đường được xây dựng trang nghiêm, là điểm tựa tâm linh cho con cháu muôn đời.";
  });
  const [regulations, setRegulations] = useState<string[]>(() => {
    const saved = localStorage.getItem('clan_regulations');
    return saved ? JSON.parse(saved) : [
      "Luôn giữ gìn và phát huy truyền thống tốt đẹp của dòng họ, tôn trọng các bậc tiền bối, yêu thương đùm bọc con cháu.",
      "Khuyến khích con cháu thi đua học tập, lao động sản xuất, đóng góp công sức xây dựng quê hương, dòng họ ngày càng giàu đẹp.",
      "Thực hiện tốt nghĩa vụ công dân, chấp hành pháp luật của Nhà nước và các quy định của địa phương.",
      "Tham gia đầy đủ các hoạt động của dòng họ, đặc biệt là các ngày giỗ tổ, chạp họ hàng năm.",
      "Giữ gìn sự đoàn kết nội bộ, giải quyết các mâu thuẫn trên tinh thần hòa giải, trọng tình trọng nghĩa."
    ];
  });

  // Admin states
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [password, setPassword] = useState('');
  const [editingMember, setEditingMember] = useState<FamilyMember | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);
  const [isEditingText, setIsEditingText] = useState(false);

  // Persistence triggers
  useEffect(() => { localStorage.setItem('clan_news', JSON.stringify(news)); }, [news]);
  useEffect(() => { localStorage.setItem('clan_tree', JSON.stringify(familyTree)); }, [familyTree]);
  useEffect(() => { localStorage.setItem('clan_banner', bannerUrl); }, [bannerUrl]);
  useEffect(() => { localStorage.setItem('clan_address', address); }, [address]);
  useEffect(() => { localStorage.setItem('clan_history', historyText); }, [historyText]);
  useEffect(() => { localStorage.setItem('clan_house_text', ancestralHouseText); }, [ancestralHouseText]);
  useEffect(() => { localStorage.setItem('clan_regulations', JSON.stringify(regulations)); }, [regulations]);

  // Initial History generation if default
  useEffect(() => {
    if (historyText === "Lịch sử dòng họ đang được cập nhật...") {
      const fetchHistory = async () => {
        const data = await generateClanHistory(CLAN_NAME, address);
        if (data) setHistoryText(data);
      };
      fetchHistory();
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') {
      setIsAdmin(true);
      setShowLogin(false);
      setPassword('');
    } else {
      alert('Sai mật khẩu! (Gợi ý: admin123)');
    }
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setIsEditingText(false);
    setEditingMember(null);
    setEditingNews(null);
  };

  const handleBannerUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setBannerUrl(base64String);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveNews = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingNews) return;
    if (news.find(n => n.id === editingNews.id)) {
      setNews(news.map(n => n.id === editingNews.id ? editingNews : n));
    } else {
      setNews([editingNews, ...news]);
    }
    setEditingNews(null);
  };

  const saveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingMember) return;
    const updateNode = (node: FamilyMember): FamilyMember => {
      if (node.id === editingMember.id) return editingMember;
      if (node.children) {
        return { ...node, children: node.children.map(updateNode) };
      }
      return node;
    };
    setFamilyTree(updateNode(familyTree));
    setEditingMember(null);
  };

  const addChild = (parentId: string) => {
    const newId = `child-${Date.now()}`;
    const newChild: FamilyMember = {
      id: newId,
      name: 'Tên thành viên mới',
      generation: 0,
      isMale: true,
      spouseName: ''
    };

    const addNode = (node: FamilyMember): FamilyMember => {
      if (node.id === parentId) {
        const updatedChild = { ...newChild, generation: node.generation + 1 };
        return { ...node, children: [...(node.children || []), updatedChild] };
      }
      if (node.children) return { ...node, children: node.children.map(addNode) };
      return node;
    };
    setFamilyTree(addNode(familyTree));
  };

  const renderSection = () => {
    switch (activeSection) {
      case AppSection.NEWS:
        return (
          <div className="animate-fadeIn">
            {isAdmin && (
              <div className="mb-8 flex justify-center">
                <button onClick={() => setEditingNews({ id: Date.now().toString(), title: '', date: new Date().toLocaleDateString('vi-VN'), summary: '', content: '', imageUrl: 'https://picsum.photos/800/400' })} className="bg-green-700 text-white px-6 py-2 rounded-full font-bold shadow-lg hover:bg-green-800 transition-colors flex items-center gap-2">Thêm Tin Tức</button>
              </div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {news.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-lg overflow-hidden border border-gold/20 relative group">
                  {isAdmin && (
                    <div className="absolute top-2 right-2 flex gap-2 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => setEditingNews(item)} className="bg-yellow-500 text-white p-2 rounded-full shadow hover:bg-yellow-600">Sửa</button>
                      <button onClick={() => setNews(news.filter(n => n.id !== item.id))} className="bg-red-600 text-white p-2 rounded-full shadow hover:bg-red-700">Xóa</button>
                    </div>
                  )}
                  <img src={item.imageUrl} alt={item.title} className="w-full h-48 object-cover" />
                  <div className="p-6">
                    <span className="text-xs font-bold text-red-600 uppercase tracking-widest">{item.date}</span>
                    <h3 className="text-xl font-bold text-red-900 mt-2 mb-3">{item.title}</h3>
                    <p className="text-gray-600 text-sm line-clamp-3">{item.summary}</p>
                    <button className="mt-4 text-red-800 font-bold hover:underline">Xem chi tiết →</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case AppSection.TREE:
        return <FamilyTree root={familyTree} isAdmin={isAdmin} onEditMember={setEditingMember} onAddChild={addChild} />;
      case AppSection.CHRONICLES:
        return (
          <div className="prose prose-lg max-w-none bg-white p-10 rounded-xl shadow-lg border-2 border-double border-gold animate-fadeIn">
            <div className="flex justify-between items-center border-b-2 border-gold pb-4 mb-6">
               <h2 className="text-3xl font-traditional text-red-900 italic m-0">Phả Kỹ Dòng Họ</h2>
               {isAdmin && (
                 <button onClick={() => setIsEditingText(!isEditingText)} className={`px-4 py-1 rounded text-sm uppercase transition-colors ${isEditingText ? 'bg-green-700 text-white' : 'bg-red-800 text-white'}`}>
                   {isEditingText ? "Lưu lại" : "Chỉnh sửa"}
                 </button>
               )}
            </div>
            {isEditingText && isAdmin ? (
              <textarea 
                value={historyText} 
                onChange={(e) => setHistoryText(e.target.value)}
                className="w-full h-96 p-4 border-2 border-gold/30 rounded font-sans text-base leading-relaxed focus:border-red-800 outline-none"
                placeholder="Nhập lịch sử dòng họ..."
              />
            ) : (
              <div className="whitespace-pre-wrap leading-relaxed text-gray-800 font-medium">
                {historyText}
              </div>
            )}
          </div>
        );
      case AppSection.ANCESTRAL_HOUSE:
        return (
          <div className="bg-white p-8 rounded-xl shadow-lg border border-gold animate-fadeIn">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-3xl font-traditional text-red-900 m-0">Từ Đường Dòng Họ</h2>
              {isAdmin && (
                <button onClick={() => setIsEditingText(!isEditingText)} className={`px-4 py-1 rounded text-sm uppercase transition-colors ${isEditingText ? 'bg-green-700 text-white' : 'bg-red-800 text-white'}`}>
                  {isEditingText ? "Lưu lại" : "Sửa mô tả"}
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <div className="flex items-center gap-2 group">
                  <p className="text-lg"><strong>Địa chỉ:</strong> {address}</p>
                  {isAdmin && (
                    <button onClick={() => { const a = prompt('Địa chỉ mới:', address); if(a) setAddress(a); }} className="text-xs text-blue-600 opacity-0 group-hover:opacity-100 underline">Sửa</button>
                  )}
                </div>
                {isEditingText && isAdmin ? (
                  <textarea 
                    value={ancestralHouseText} 
                    onChange={(e) => setAncestralHouseText(e.target.value)}
                    className="w-full h-48 p-4 border-2 border-gold/30 rounded focus:border-red-800 outline-none"
                    placeholder="Nhập mô tả về từ đường..."
                  />
                ) : (
                  <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{ancestralHouseText}</p>
                )}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <img src="https://picsum.photos/seed/house1/400/300" alt="Từ đường 1" className="rounded-lg shadow hover:scale-105 transition-transform" />
                <img src="https://picsum.photos/seed/house2/400/300" alt="Từ đường 2" className="rounded-lg shadow hover:scale-105 transition-transform" />
                <img src="https://picsum.photos/seed/house3/400/300" alt="Từ đường 3" className="rounded-lg shadow hover:scale-105 transition-transform" />
                <img src="https://picsum.photos/seed/house4/400/300" alt="Từ đường 4" className="rounded-lg shadow hover:scale-105 transition-transform" />
              </div>
            </div>
          </div>
        );
      case AppSection.REGULATIONS:
        return (
          <div className="max-w-4xl mx-auto bg-[#fffdf0] p-12 shadow-2xl rounded-sm border-[16px] border-double border-red-900 relative animate-fadeIn">
             <div className="flex justify-between items-center mb-10">
               <div className="w-10"></div>
               <h2 className="text-4xl font-traditional text-red-900 m-0 uppercase tracking-widest">Tộc Ước Dòng Họ</h2>
               {isAdmin ? (
                  <button onClick={() => setIsEditingText(!isEditingText)} className={`px-4 py-1 rounded text-xs uppercase transition-colors ${isEditingText ? 'bg-green-700 text-white' : 'bg-red-800 text-white'}`}>
                    {isEditingText ? "Lưu lại" : "Sửa tộc ước"}
                  </button>
               ) : <div className="w-10"></div>}
             </div>

             {isEditingText && isAdmin ? (
               <textarea 
                 value={regulations.join('\n')}
                 onChange={(e) => setRegulations(e.target.value.split('\n'))}
                 className="w-full h-80 p-6 border-4 border-double border-gold/50 bg-white font-serif text-lg leading-loose focus:outline-none"
                 placeholder="Nhập mỗi điều tộc ước trên một dòng..."
               />
             ) : (
               <div className="space-y-6 text-lg text-red-950 italic">
                 {regulations.filter(r => r.trim()).map((reg, idx) => (
                   <p key={idx}><strong>Điều {idx + 1}:</strong> {reg}</p>
                 ))}
               </div>
             )}
             <div className="mt-12 text-center text-sm text-red-800 italic">- Trích lục từ bản gốc lưu tại Từ Đường -</div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-20 overflow-x-hidden">
      {/* Header Banner */}
      <header className="relative w-full h-[300px] md:h-[500px] flex items-center justify-center bg-cover bg-center shadow-2xl border-b-8 border-gold overflow-hidden">
        <img src={bannerUrl} alt="Banner" className="absolute inset-0 w-full h-full object-cover transition-opacity duration-1000" />

        {isAdmin && (
          <div className="absolute top-4 right-4 z-20 flex gap-2">
            <input 
              type="file" 
              accept="image/*" 
              className="hidden" 
              ref={bannerInputRef}
              onChange={handleBannerUpload}
            />
            <button 
              onClick={() => bannerInputRef.current?.click()}
              className="bg-black/60 text-white px-4 py-2 rounded-lg border border-gold hover:bg-black transition-colors flex items-center gap-2 shadow-lg"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              Tải ảnh bìa
            </button>
            <button 
              onClick={() => { const url = prompt('Hoặc nhập URL ảnh:', bannerUrl); if(url) setBannerUrl(url); }}
              className="bg-black/40 text-white px-4 py-2 rounded-lg border border-gold/30 hover:bg-black/60 transition-colors text-xs"
            >
              Dùng URL
            </button>
          </div>
        )}

        <div className="absolute bottom-6 w-full text-center z-10">
          <div className="inline-block bg-black/40 backdrop-blur-sm px-6 py-2 rounded-full border border-gold/50 shadow-lg group">
            <p className="text-white font-medium flex items-center gap-2">
              Địa chỉ: <span className="text-gold font-bold">{address}</span>
              {isAdmin && (
                <button onClick={() => { const a = prompt('Địa chỉ:', address); if(a) setAddress(a); }} className="text-[10px] text-white/50 hover:text-white underline">Sửa</button>
              )}
            </p>
          </div>
        </div>
      </header>

      {/* Admin Mode Bar */}
      {isAdmin && (
        <div className="bg-red-900 text-gold text-center py-2 font-bold uppercase text-xs flex justify-center items-center gap-8 shadow-inner sticky top-0 z-[100] border-b border-gold/20">
          <div className="flex items-center gap-2">
            <span className="animate-pulse h-2 w-2 rounded-full bg-gold"></span>
            CHẾ ĐỘ QUẢN TRỊ VIÊN
          </div>
          <button 
            onClick={handleLogout} 
            className="bg-gold text-red-950 px-3 py-1 rounded hover:bg-yellow-300 transition-colors font-bold shadow-md"
          >
            THOÁT & ĐĂNG XUẤT
          </button>
        </div>
      )}

      <div className="max-w-7xl mx-auto px-4 mt-[-40px] relative z-20">
        <Navigation activeSection={activeSection} onSectionChange={(s) => { setActiveSection(s); setIsEditingText(false); }} />
        <main className="mt-8">{renderSection()}</main>
      </div>

      {showLogin && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-md shadow-2xl animate-fadeIn">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Đăng nhập Quản trị</h3>
            <form onSubmit={handleLogin} className="space-y-4">
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="w-full border-2 border-gray-200 rounded-lg px-4 py-3 focus:border-red-800 outline-none transition-all" 
                placeholder="Nhập mật khẩu..." 
                autoFocus 
              />
              <div className="flex gap-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg hover:bg-red-900 shadow-lg">Đăng nhập</button>
                <button type="button" onClick={() => setShowLogin(false)} className="flex-1 bg-gray-100 py-3 rounded-lg hover:bg-gray-200">Hủy</button>
              </div>
              <p className="text-center text-[10px] text-gray-400 mt-2 italic">Gợi ý: admin123</p>
            </form>
          </div>
        </div>
      )}

      {editingMember && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Biên tập thành viên</h3>
            <form onSubmit={saveMember} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Họ và Tên</label>
                  <input type="text" value={editingMember.name} onChange={(e) => setEditingMember({...editingMember, name: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 focus:border-red-800 outline-none" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Vợ / Chồng</label>
                  <input type="text" value={editingMember.spouseName || ''} onChange={(e) => setEditingMember({...editingMember, spouseName: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 focus:border-red-800 outline-none" placeholder="Tên vợ hoặc chồng..." />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Giới tính</label>
                  <select value={editingMember.isMale ? 'male' : 'female'} onChange={(e) => setEditingMember({...editingMember, isMale: e.target.value === 'male'})} className="w-full border-2 rounded-lg px-4 py-2 focus:border-red-800 outline-none">
                    <option value="male">Nam</option>
                    <option value="female">Nữ</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Năm sinh</label>
                  <input type="text" value={editingMember.birthDate || ''} onChange={(e) => setEditingMember({...editingMember, birthDate: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 focus:border-red-800 outline-none" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Tiểu sử</label>
                <textarea value={editingMember.bio || ''} onChange={(e) => setEditingMember({...editingMember, bio: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 h-20 focus:border-red-800 outline-none" />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg shadow-lg hover:bg-red-900">Lưu lại</button>
                <button type="button" onClick={() => setEditingMember(null)} className="flex-1 bg-gray-100 py-3 rounded-lg hover:bg-gray-200">Đóng</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {editingNews && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-traditional text-red-900 mb-6 text-center">Biên tập tin tức</h3>
            <form onSubmit={saveNews} className="space-y-4">
              <input type="text" value={editingNews.title} onChange={(e) => setEditingNews({...editingNews, title: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 focus:border-red-800 outline-none" placeholder="Tiêu đề..." required />
              <textarea value={editingNews.summary} onChange={(e) => setEditingNews({...editingNews, summary: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 h-20 focus:border-red-800 outline-none" placeholder="Tóm tắt..." required />
              <textarea value={editingNews.content} onChange={(e) => setEditingNews({...editingNews, content: e.target.value})} className="w-full border-2 rounded-lg px-4 py-2 h-40 focus:border-red-800 outline-none" placeholder="Nội dung chi tiết..." required />
              <div className="flex gap-4">
