      </div>

      {/* Nhánh con */}
      {hasChildren && isExpanded && (
        <div className="relative mt-16 animate-fadeIn">
          {/* Đường kẻ dọc từ cha xuống (tăng chiều dài để rõ ràng hơn giữa đời 1-2) */}
          <div className="absolute top-[-64px] left-1/2 w-0.5 h-16 bg-gold -translate-x-1/2 shadow-[0_0_2px_rgba(212,175,55,0.5)]" />

