            {member.children!.length > 1 && (
              <div 
                className="absolute top-0 left-0 right-0 h-0.5 bg-gold mx-auto" 
                style={{ 
                  width: `calc(100% - ${100/member.children!.length}%)` 
                }} 
              />
            )}

            {member.children!.map((child) => (
              <div key={child.id} className="relative pt-8 flex flex-col items-center">
                {/* Đường kẻ dọc ngắn xuống mỗi con */}
                <div className="absolute top-0 left-1/2 w-0.5 h-8 bg-gold -translate-x-1/2 shadow-[0_0_1px_rgba(212,175,55,0.3)]" />
                <MemberNode member={child} isAdmin={isAdmin} onEdit={onEdit} onAddChild={onAddChild} />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

