          <div className="hidden md:block absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-[3px] bg-gradient-to-r from-transparent via-gold/50 to-transparent -z-10"></div>
        )}

        {/* Thẻ thành viên chính */}
        <div className={`
          p-4 rounded-2xl border-[4px] shadow-xl w-52 text-center relative z-10
          transition-all duration-300 transform group-hover:shadow-[0_15px_35px_rgba(139,0,0,0.25)] group-hover:-translate-y-2
          ${member.isMale ? 'bg-blue-50 border-blue-500/60' : 'bg-pink-50 border-pink-500/60'}
          ${isGen1To2 ? 'ring-4 ring-gold/30 ring-offset-2' : ''}
        `}>
          {isAdmin && (
            <div className="absolute -top-4 -left-4 flex gap-1 z-30 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); onEdit?.(member); }}
                className="bg-yellow-500 text-white p-2 rounded-full hover:bg-yellow-600 shadow-lg border-2 border-white transition-transform hover:scale-110"
                title="Sửa thông tin"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                </svg>
              </button>
            </div>
