          <div className="font-bold text-red-900 text-xl font-traditional truncate px-1 drop-shadow-sm" title={member.name}>
            {member.name}
          </div>

          <div className="flex flex-col gap-1 mt-2">
            <div className={`text-[10px] font-black uppercase tracking-widest rounded-full py-0.5 ${isGen1To2 ? 'bg-gold text-red-950 px-3' : 'bg-red-50 text-red-800/70'}`}>
              {isGen1To2 ? 'Cụ Tổ (Đời 1)' : `Đời Thứ ${member.generation}`}
            </div>
            {member.parentName && (
              <div className="text-[10px] text-blue-800 bg-blue-100/50 rounded-md py-0.5 px-2 border border-blue-200 mt-1">
                <span className="opacity-60">Con cụ:</span> <span className="font-bold">{member.parentName}</span>
              </div>
            )}
            {member.birthDate && (
              <div className="text-[10px] text-gray-500 font-medium italic">
                {member.birthDate}
              </div>
            )}
          </div>
        </div>

        {/* Thẻ Vợ/Chồng */}
