        {/* Nút thêm con */}
        {isAdmin && (
          <button 
            onClick={() => onAddChild?.(member)}
            className="absolute -right-10 top-1/2 -translate-y-1/2 bg-green-600 text-white p-2 rounded-full hover:bg-green-700 shadow-xl z-30 opacity-0 group-hover:opacity-100 transition-all hover:scale-125 border-2 border-white"
