            </svg>
          </button>
        )}

        {/* Nút thu gọn/mở rộng */}
        {hasChildren && (
          <button
            onClick={toggleExpand}
            className={`
              absolute left-1/2 -bottom-6 -translate-x-1/2 z-20
              w-10 h-10 rounded-full border-[3px] shadow-2xl
