          </div>

          <div className={`flex gap-20 justify-center relative px-32`}>
            {/* Thanh ngang (Bridge) nối các con */}
            {member.children!.length > 1 && (
              <div 
                className={`absolute top-0 left-0 right-0 mx-auto shadow-[0_2px_10px_rgba(0,0,0,0.15)] rounded-full
