                  ${isGen1To2 ? 'h-[6px] bg-gold' : 'h-[4px] bg-gold/80'}
                `} 
                style={{ 
                  width: `calc(100% - ${100/member.children!.length}%)` 
                }} 
              />
            )}

            {member.children!.map((child) => (
              <div key={child.id} className="relative pt-12 flex flex-col items-center">
                <div className={`absolute top-0 left-1/2 -translate-x-1/2 shadow-sm
                  ${isGen1To2 ? 'w-[5px] h-12 bg-gold' : 'w-[3px] h-12 bg-gold/70'}
                `} />
                <MemberNode member={child} isAdmin={isAdmin} onEdit={onEdit} onAddChild={onAddChild} />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const FamilyTree: React.FC<{ 
  root: FamilyMember; 
  isAdmin?: boolean; 
  onEditMember?: (m: FamilyMember) => void; 
  onAddChild?: (parent: FamilyMember) => void 
}> = ({ root, isAdmin = false, onEditMember, onAddChild }) => {
  const [scale, setScale] = useState(0.8);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.1, 2));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.1, 0.2));
  const handleResetZoom = () => setScale(0.8);

  // Mouse wheel zoom support
  useEffect(() => {
    const handleWheel = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault();
        if (e.deltaY < 0) handleZoomIn();
        else handleZoomOut();
      }
    };
    const container = containerRef.current;
    if (container) {
      container.addEventListener('wheel', handleWheel, { passive: false });
    }
    return () => {
      if (container) {
        container.removeEventListener('wheel', handleWheel);
      }
    };
  }, []);

  return (
    <div className="bg-white/40 backdrop-blur-md rounded-[2.5rem] border-[6px] border-double border-gold/30 shadow-2xl p-6 md:p-16 overflow-hidden relative min-h-[800px]">

      {/* Nút điều khiển Zoom (Floating Controls) */}
