        <div className="bg-red-900/95 backdrop-blur-md shadow-2xl rounded-3xl p-3 border-2 border-gold/60 flex flex-col gap-3 group">
          <button 
            onClick={handleZoomIn}
            className="w-14 h-14 flex items-center justify-center text-gold hover:bg-gold hover:text-red-900 rounded-2xl transition-all active:scale-90 shadow-lg border border-gold/20"
            title="Phóng to (Ctrl + Cuộn chuột)"
          >
