              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
            </svg>
          </button>

          <div className="flex items-center justify-center text-[12px] font-black text-gold bg-red-950/50 py-1 rounded-lg border border-gold/10">
            {Math.round(scale * 100)}%
          </div>

          <button 
            onClick={handleZoomOut}
            className="w-14 h-14 flex items-center justify-center text-gold hover:bg-gold hover:text-red-900 rounded-2xl transition-all active:scale-90 shadow-lg border border-gold/20"
            title="Thu nhỏ (Ctrl + Cuộn chuột)"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M20 12H4" />
            </svg>
          </button>

          <div className="h-px bg-gold/30 mx-3"></div>

          <button 
            onClick={handleResetZoom}
            className="w-14 h-14 flex flex-col items-center justify-center text-gold hover:bg-gold hover:text-red-900 rounded-2xl transition-all shadow-lg border border-gold/20 group/reset"
            title="Về mặc định"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
            </svg>
            <span className="text-[9px] font-black uppercase tracking-tighter">RESET</span>
          </button>
        </div>
        <p className="text-[9px] text-center font-bold text-red-950 bg-gold/80 py-1 rounded-full shadow-md border border-red-900/10 italic">
          Ctrl + Cuộn chuột để Zoom
        </p>
      </div>

      {/* Header Phả Đồ */}
      <div className="text-center mb-32 relative">
        <div className="absolute -top-16 left-1/2 -translate-x-1/2 opacity-5 pointer-events-none scale-150">
           <svg viewBox="0 0 100 100" className="w-64 h-64 fill-red-900">
             <path d="M50 10 L60 40 L90 40 L65 60 L75 90 L50 70 L25 90 L35 60 L10 40 L40 40 Z" />
           </svg>
        </div>
        <h3 className="text-5xl font-traditional text-red-900 italic mb-4 tracking-[0.2em] uppercase drop-shadow-lg">Đại Bản Đồ Phả Hệ</h3>
        <p className="text-gray-700 max-w-xl mx-auto italic font-bold text-lg opacity-80">"Nước có nguồn, cây có cội - Con cháu sum vầy, dòng họ trường tồn"</p>
        <div className="flex items-center justify-center gap-4 mt-6">
          <div className="w-20 h-px bg-gold"></div>
          <div className="w-3 h-3 bg-red-800 rotate-45 border border-gold"></div>
          <div className="w-32 h-1 bg-gradient-to-r from-transparent via-gold to-transparent"></div>
          <div className="w-3 h-3 bg-red-800 rotate-45 border border-gold"></div>
          <div className="w-20 h-px bg-gold"></div>
        </div>
      </div>

      {/* Không gian vẽ cây với Zoom & Pan */}
      <div 
        ref={containerRef}
        className="overflow-x-auto overflow-y-auto min-h-[700px] pb-60 pt-10 cursor-move scrollbar-hide active:cursor-grabbing"
      >
        <div 
          className="inline-block transition-transform duration-500 origin-top ease-[cubic-bezier(0.23,1,0.32,1)]"
          style={{ transform: `scale(${scale})` }}
        >
          <div className="px-[30rem] py-20">
            <MemberNode member={root} isAdmin={isAdmin} onEdit={onEditMember} onAddChild={onAddChild} />
          </div>
        </div>
      </div>

      {/* Legend & Instructions */}
      <div className="absolute bottom-10 left-10 z-40 bg-white/95 backdrop-blur-sm p-6 rounded-[2rem] border-2 border-gold/30 shadow-2xl text-[12px] font-bold text-red-950 flex flex-col gap-3">
        <h5 className="uppercase tracking-widest border-b border-gold/20 pb-2 mb-1 text-center font-black">Chú Giải Phả Đồ</h5>
        <div className="flex items-center gap-3">
          <span className="w-4 h-4 bg-blue-100 border-2 border-blue-500 rounded-md shadow-sm"></span>
          <span>Thành viên Nam</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="w-4 h-4 bg-pink-100 border-2 border-pink-500 rounded-md shadow-sm"></span>
          <span>Thành viên Nữ</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="w-4 h-4 border-2 border-dashed border-gray-400 rounded-md bg-gray-50"></span>
          <span>Phối ngẫu (Vợ/Chồng)</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="w-10 h-1.5 bg-gold rounded-full shadow-[0_0_5px_rgba(212,175,55,0.5)]"></span>
          <span>Đường huyết thống</span>
        </div>
        <div className="mt-2 pt-2 border-t border-gold/10 flex items-center gap-2">
          <div className="bg-red-800 text-white px-2 py-0.5 rounded text-[9px] uppercase">Mẹo</div>
          <p className="italic text-[10px] opacity-60">Giữ Ctrl + Cuộn chuột để Phóng to/Thu nhỏ</p>
        </div>
      </div>
    </div>
  );
};

export default FamilyTree;

