      {hasChildren && isExpanded && (
        <div className="relative mt-24 animate-fadeIn">
          {/* Main vertical connector from parent */}
          <div className={`
            absolute top-[-96px] left-1/2 -translate-x-1/2 rounded-full shadow-[0_5px_15px_rgba(212,175,55,0.4)]
            ${isGen1To2 
              ? 'w-[10px] h-24 bg-gradient-to-b from-red-900 via-gold to-gold z-0 ring-2 ring-red-800/20' 
              : 'w-[4px] h-24 bg-gold opacity-80 z-0'}
          `} />

          {/* Connector joint point */}
          <div className={`
