interface FamilyTreeProps {
  root: FamilyMember;
  isAdmin: boolean;
  onEditMember: (member: FamilyMember) => void;
  onAddChild: (parent: FamilyMember) => void;
}

const FamilyTree: React.FC<FamilyTreeProps> = ({ root, isAdmin, onEditMember, onAddChild }) => {
  const [scale, setScale] = useState(0.8);
  const containerRef = useRef<HTMLDivElement>(null);

  // States cho tính năng kéo thả (Pan)
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [startY, setStartY] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);
  const [scrollTop, setScrollTop] = useState(0);

  // Xử lý zoom
  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.1, 2.5));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.1, 0.2));
  const handleResetZoom = () => setScale(0.8);

  // Xử lý kéo thả để di chuyển (Drag-to-Pan)
  const onMouseDown = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    setIsDragging(true);
    setStartX(e.pageX - containerRef.current.offsetLeft);
    setStartY(e.pageY - containerRef.current.offsetTop);
    setScrollLeft(containerRef.current.scrollLeft);
    setScrollTop(containerRef.current.scrollTop);
  };

  const onMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    e.preventDefault();
    const x = e.pageX - containerRef.current.offsetLeft;
    const y = e.pageY - containerRef.current.offsetTop;
    const walkX = (x - startX) * 1.5;
    const walkY = (y - startY) * 1.5;
    containerRef.current.scrollLeft = scrollLeft - walkX;
    containerRef.current.scrollTop = scrollTop - walkY;
  };

  const onMouseUpOrLeave = () => setIsDragging(false);

  // Hiệu ứng zoom bằng con lăn chuột và pinch-to-zoom trên di động
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // Zoom bằng Wheel
    const handleWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const delta = e.deltaY < 0 ? 0.05 : -0.05;
        setScale(prev => Math.min(Math.max(prev + delta, 0.2), 2.5));
      }
    };

    // Pinch zoom trên thiết bị di động
    let initialDist = 0;
    const handleTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 2) {
        e.preventDefault();
        const dist = Math.hypot(
          e.touches[0].pageX - e.touches[1].pageX,
          e.touches[0].pageY - e.touches[1].pageY
        );
        if (initialDist === 0) {
          initialDist = dist;
        } else {
          const delta = dist / initialDist;
          if (Math.abs(delta - 1) > 0.01) {
            setScale(prev => Math.min(Math.max(prev * delta, 0.2), 2.5));
            initialDist = dist;
          }
        }
      }
    };

    const handleTouchEnd = () => { initialDist = 0; };

    container.addEventListener('wheel', handleWheel, { passive: false });
    container.addEventListener('touchmove', handleTouchMove, { passive: false });
    container.addEventListener('touchend', handleTouchEnd);

    return () => {
      container.removeEventListener('wheel', handleWheel);
      container.removeEventListener('touchmove', handleTouchMove);
      container.removeEventListener('touchend', handleTouchEnd);
    };
  }, []);

  return (
    <div className="relative w-full overflow-hidden bg-white/40 backdrop-blur-md rounded-3xl border-2 border-black/5 shadow-2xl min-h-[750px]">

      {/* Bộ điều khiển Zoom */}
      <div className="absolute top-6 right-6 z-50 flex flex-col gap-3">
        <div className="bg-black/90 backdrop-blur-lg shadow-2xl rounded-2xl p-2 border border-white/20 flex flex-col gap-2">
          <button 
            onClick={handleZoomIn}
            className="w-10 h-10 flex items-center justify-center bg-white/10 text-white hover:bg-white hover:text-black rounded-xl transition-all shadow-md active:scale-90"
            title="Phóng to"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
            </svg>
          </button>

          <div className="text-center font-bold text-[10px] text-white/90 border-y border-white/10 py-1">
            {Math.round(scale * 100)}%
          </div>

          <button 
            onClick={handleZoomOut}
            className="w-10 h-10 flex items-center justify-center bg-white/10 text-white hover:bg-white hover:text-black rounded-xl transition-all shadow-md active:scale-90"
            title="Thu nhỏ"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M20 12H4" />
            </svg>
          </button>

          <button 
            onClick={handleResetZoom}
            className="w-10 h-10 flex items-center justify-center bg-white/10 text-white hover:bg-white hover:text-black rounded-xl transition-all shadow-md active:scale-90"
            title="Mặc định"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        </div>

        {/* Legend / Ghi chú */}
        <div className="bg-white/95 backdrop-blur-md p-3 rounded-xl border border-black/10 shadow-xl hidden md:block">
          <h5 className="text-[9px] font-black uppercase text-black mb-2 border-b border-black/10 pb-1">Đường huyết thống</h5>
          <div className="space-y-1.5 text-[9px] text-gray-700 font-bold">
            <p className="flex items-center gap-2"><span className="w-1.5 h-1.5 rounded-full bg-black"></span> Đường line đen: Cha -> Con</p>
            <p className="flex items-center gap-2"><span className="w-1.5 h-1.5 rounded-full bg-red-900"></span> Nút đỏ: Gốc tổ (Đời 1)</p>
            <p className="flex items-center gap-2"><span className="w-1.5 h-1.5 rounded-full bg-gray-400"></span> Giữ chuột để di chuyển cây</p>
          </div>
        </div>
      </div>

      {/* Canvas chính chứa cây phả hệ */}
      <div 
        ref={containerRef}
        onMouseDown={onMouseDown}
        onMouseMove={onMouseMove}
        onMouseUp={onMouseUpOrLeave}
        onMouseLeave={onMouseUpOrLeave}
        className={`
          w-full h-full overflow-auto pt-20 pb-80 px-[40rem] scrollbar-hide
          ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}
        `}
      >
        <div 
          style={{ 
            transform: `scale(${scale})`, 
            transformOrigin: 'top center',
            transition: isDragging ? 'none' : 'transform 0.2s cubic-bezier(0.4, 0, 0.2, 1)' 
          }}
          className="inline-block"
        >
          <MemberNode 
            member={root} 
            isAdmin={isAdmin} 
            onEdit={onEditMember} 
            onAddChild={onAddChild} 
          />
        </div>
      </div>

      {/* Background Pattern subtle grid */}
      <div className="absolute inset-0 pointer-events-none opacity-[0.05]" style={{ backgroundImage: 'radial-gradient(#000 0.5px, transparent 0.5px)', backgroundSize: '30px 30px' }}></div>
    </div>
  );
};

