        <main className="mt-8">{renderSection()}</main>
      </div>

      {/* Login Modal */}
      {showLogin && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-md shadow-[0_0_50px_rgba(212,175,55,0.3)] animate-fadeIn">
