            <form onSubmit={handleLogin} className="space-y-4">
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="w-full border-2 border-gray-200 rounded-lg px-4 py-3 focus:border-red-800 outline-none transition-all shadow-inner" 
                placeholder="Nhập mật khẩu..." 
                autoFocus 
              />
              <div className="flex gap-4 pt-2">
                <button type="submit" className="flex-1 bg-red-800 text-white font-bold py-3 rounded-lg hover:bg-red-900 shadow-lg transition-all">Đăng nhập</button>
                <button type="button" onClick={() => setShowLogin(false)} className="flex-1 bg-gray-100 py-3 rounded-lg hover:bg-gray-200 transition-all">Đóng</button>
              </div>
              <p className="text-center text-[10px] text-gray-400 mt-2 italic uppercase tracking-widest">Gợi ý: admin123</p>
            </form>
          </div>
        </div>
      )}

      {/* Edit Member Modal */}
      {editingMember && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white p-8 rounded-xl border-4 border-gold w-full max-w-lg shadow-2xl max-h-[95vh] overflow-y-auto animate-fadeIn relative">

            {/* Confirmation Overlay for Deletion */}
            {showDeleteConfirm === editingMember.id && (
              <div className="absolute inset-0 bg-red-900/95 z-50 rounded-lg flex flex-col items-center justify-center p-8 text-center animate-fadeIn">
                <div className="bg-white p-4 rounded-full mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
