               {isAdmin && (
                 <button onClick={() => setIsEditingText(!isEditingText)} className={`px-4 py-1 rounded text-sm uppercase transition-all ${isEditingText ? 'bg-green-700 text-white' : 'bg-red-800 text-white hover:bg-red-900'}`}>
                   {isEditingText ? "Hoàn tất" : "Chỉnh sửa"}
                 </button>
               )}
            </div>
            {isEditingText && isAdmin ? (
              <textarea 
                value={historyText} 
                onChange={(e) => setHistoryText(e.target.value)}
