            absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 rounded-full border-2 border-white shadow-lg z-20
            ${isGen1To2 ? 'w-6 h-6 bg-red-950' : 'w-4 h-4 bg-red-900'}
