             {member.children?.map((child, index) => (
                <div key={child.id} className="relative flex flex-col items-center px-8">

                   {/* 4. Phân đoạn đường kẻ ngang (Sibling Line Segments) */}
                   {member.children && member.children.length > 1 && (
                      <div className={`
                        absolute top-0 h-[6px] bg-red-900 shadow-[0_1px_2px_rgba(0,0,0,0.1)]
                        ${index === 0 ? 'left-1/2 right-0' : index === (member.children?.length ?? 0) - 1 ? 'left-0 right-1/2' : 'left-0 right-0'}
                      `}></div>
                   )}

                   {/* 5. Đường kẻ dọc từ line ngang xuống đầu mỗi con (Cuống nối) */}
                   <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[6px] h-12 bg-red-900 -z-10 shadow-sm"></div>

                   <div className="mt-12">
                     <MemberNode member={child} isAdmin={isAdmin} onEdit={onEdit} onAddChild={onAddChild} />
                   </div>
                </div>
             ))}
          </div>
        </div>
      )}
    </div>
  );
};

interface FamilyTreeProps {
  root: FamilyMember;
  isAdmin: boolean;
  onEditMember: (member: FamilyMember) => void;
  onAddChild: (parent: FamilyMember) => void;
}

const FamilyTree: React.FC<FamilyTreeProps> = ({ root, isAdmin, onEditMember, onAddChild }) => {
  const [scale, setScale] = useState(0.8);
  const containerRef = useRef<HTMLDivElement>(null);

  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [startY, setStartY] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);
  const [scrollTop, setScrollTop] = useState(0);

  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.1, 2.5));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.1, 0.2));
  const handleResetZoom = () => setScale(0.8);

  const onMouseDown = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    setIsDragging(true);
    setStartX(e.pageX - containerRef.current.offsetLeft);
    setStartY(e.pageY - containerRef.current.offsetTop);
    setScrollLeft(containerRef.current.scrollLeft);
    setScrollTop(containerRef.current.scrollTop);
  };

  const onMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    e.preventDefault();
    const x = e.pageX - containerRef.current.offsetLeft;
    const y = e.pageY - containerRef.current.offsetTop;
    const walkX = (x - startX) * 1.5;
    const walkY = (y - startY) * 1.5;
    containerRef.current.scrollLeft = scrollLeft - walkX;
    containerRef.current.scrollTop = scrollTop - walkY;
  };

  const onMouseUpOrLeave = () => setIsDragging(false);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const delta = e.deltaY < 0 ? 0.05 : -0.05;
        setScale(prev => Math.min(Math.max(prev + delta, 0.2), 2.5));
      }
    };

    container.addEventListener('wheel', handleWheel, { passive: false });
    return () => container.removeEventListener('wheel', handleWheel);
  }, []);

  return (
    <div className="relative w-full overflow-hidden bg-[#fdf6e3]/60 backdrop-blur-md rounded-3xl border-2 border-red-900/10 shadow-2xl min-h-[800px]">

      {/* Zoom Controls */}
      <div className="absolute top-6 right-6 z-50 flex flex-col gap-3">
        <div className="bg-red-950/90 backdrop-blur-lg shadow-2xl rounded-2xl p-2 border border-gold/30 flex flex-col gap-2">
          <button onClick={handleZoomIn} className="w-10 h-10 flex items-center justify-center bg-white/10 text-gold hover:bg-gold hover:text-red-950 rounded-xl transition-all shadow-md active:scale-90" title="Phóng to">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
          </button>
          <div className="text-center font-bold text-[10px] text-gold/90 border-y border-gold/10 py-1">{Math.round(scale * 100)}%</div>
          <button onClick={handleZoomOut} className="w-10 h-10 flex items-center justify-center bg-white/10 text-gold hover:bg-gold hover:text-red-950 rounded-xl transition-all shadow-md active:scale-90" title="Thu nhỏ">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M20 12H4" /></svg>
          </button>
          <button onClick={handleResetZoom} className="w-10 h-10 flex items-center justify-center bg-white/10 text-gold hover:bg-gold hover:text-red-950 rounded-xl transition-all shadow-md active:scale-90" title="Mặc định">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
          </button>
        </div>

        <div className="bg-white/95 backdrop-blur-md p-4 rounded-xl border border-red-900/10 shadow-xl hidden md:block">
          <h5 className="text-[10px] font-black uppercase text-red-900 mb-3 border-b border-red-900/10 pb-1 flex items-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" /></svg>
            Chú giải phả đồ
          </h5>
          <div className="space-y-2 text-[10px] text-gray-700 font-bold">
            <p className="flex items-center gap-3"><span className="w-6 h-1 bg-red-900 rounded-full"></span> Đường phả hệ (Liền mạch)</p>
            <p className="flex items-center gap-3"><span className="w-3 h-3 bg-white border border-pink-300 rounded-sm"></span> Phối ngẫu (Vợ/Chồng)</p>
          </div>
        </div>
      </div>

      {/* Main Family Tree Canvas */}
      <div 
        ref={containerRef}
        onMouseDown={onMouseDown}
        onMouseMove={onMouseMove}
        onMouseUp={onMouseUpOrLeave}
        onMouseLeave={onMouseUpOrLeave}
        className={`w-full h-full overflow-auto pt-24 pb-96 px-[60rem] scrollbar-hide ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}
      >
        <div 
          style={{ 
            transform: `scale(${scale})`, 
            transformOrigin: 'top center',
            transition: isDragging ? 'none' : 'transform 0.2s cubic-bezier(0.4, 0, 0.2, 1)' 
          }}
          className="inline-block"
        >
          <MemberNode 
            member={root} 
            isAdmin={isAdmin} 
            onEdit={onEditMember} 
