      <div className="absolute inset-0 pointer-events-none opacity-[0.04]" style={{ backgroundImage: 'radial-gradient(#8b0000 0.8px, transparent 0.8px)', backgroundSize: '50px 50px' }}></div>
    </div>
  );
};

