              : `left-1/2 -translate-x-1/2 top-[-64px] w-[6px] h-[70px] ${isGen1To2 ? 'bg-red-950 w-[8px]' : ''}` // Đường nối ngang cho đời 1-3
            }
          `} />

          <div className={`flex ${isVerticalLayout ? 'flex-col gap-6' : 'flex-row justify-center'} relative w-full`}>
             {member.children?.map((child, index) => {
                const isLast = index === (member.children?.length ?? 0) - 1;
                return (
                  <div key={child.id} className="relative flex flex-col items-center px-6">
                     {/* Đường nối cho bố cục ngang (Đời 1-3) */}
                     {!isVerticalLayout && member.children && member.children.length > 1 && (
                        <div className={`
                          absolute top-0 h-[6px] bg-red-900
                          ${index === 0 ? 'left-1/2 right-0' : isLast ? 'left-0 right-1/2' : 'left-0 right-0'}
