                        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[6px] h-10 bg-red-900 -z-10 shadow-sm"></div>
                     )}

                     {/* Đường nối cho bố cục dọc (Đời 4+) - Nhánh ngang từ cột đứng */}
                     {isVerticalLayout && (
                        <>
                          <div className="absolute left-[-20px] top-1/2 -translate-y-1/2 w-[20px] h-[6px] bg-red-900 -z-10"></div>
                          {/* Che đường dọc dư thừa ở phần tử cuối */}
                          {isLast && (
                            <div className="absolute left-[-20px] top-1/2 bottom-0 w-[6px] bg-[#fdf6e3] -z-[5]"></div>
                          )}
                        </>
                     )}

                     <div className={isVerticalLayout ? '' : 'mt-10'}>
                       <MemberNode member={child} isAdmin={isAdmin} onEdit={onEdit} onAddChild={onAddChild} />
                     </div>
                  </div>
                );
             })}
          </div>
        </div>
      )}
    </div>
  );
};

