        className={`w-full h-full overflow-auto pt-20 pb-60 px-[60rem] scrollbar-hide ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}
      >
        <div 
          ref={treeRef}
          style={{ 
            transform: `scale(${scale})`, 
