              </div>
              <div className="p-12 space-y-10">
                <div className="flex flex-col md:flex-row gap-8 items-start">
                  <div className="flex-1 space-y-6">
                    <div className="flex items-center justify-between">
                      <div className="bg-red-900 text-gold px-6 py-3 rounded-2xl font-bold flex items-center gap-3 shadow-lg">
                        <span className="text-2xl">📍</span>
                        <span className="text-lg">{address}</span>
                      </div>
                      {isAdmin && (
                        <button onClick={() => { const a = prompt('Nhập địa chỉ mới:', address); if(a) setAddress(a); }} className="text-red-800 font-bold underline hover:text-red-950">Đổi địa chỉ</button>
                      )}
                    </div>
                    {isEditingText && isAdmin ? (
                      <textarea value={ancestralHouseText} onChange={(e) => setAncestralHouseText(e.target.value)} className="w-full h-64 p-6 border-2 border-red-100 rounded-2xl bg-red-50/20 focus:border-red-800 outline-none text-gray-700 leading-relaxed text-lg" />
                    ) : (
                      <p className="text-gray-700 leading-loose whitespace-pre-wrap text-xl italic font-medium border-l-8 border-red-900/20 pl-10 py-4">
                        {ancestralHouseText}
                      </p>
                    )}
                    {isAdmin && (
                      <button onClick={() => setIsEditingText(!isEditingText)} className="bg-red-50 text-red-900 px-6 py-2 rounded-full font-bold hover:bg-red-100 transition-all">
                        {isEditingText ? "Lưu mô tả" : "Chỉnh sửa mô tả"}
                      </button>
                    )}
                  </div>
                  <div className="w-full md:w-80 grid grid-cols-2 gap-4">
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">🏮</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Tết Cổ Truyền</span>
                     </div>
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">🍱</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Lễ Chạp Họ</span>
                     </div>
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">🏵️</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Tổ Tiên</span>
                     </div>
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
