interface EventsProps {
  events: EventItem[];
  isAdmin: boolean;
  onAddEvent: (event: EventItem) => void;
  onDeleteEvent: (id: string) => void;
}

const Events: React.FC<EventsProps> = ({ events, isAdmin, onAddEvent, onDeleteEvent }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Mock Lunar Data Logic (Simplified for UI representation)
  // In a real app, a full lunar calendar library would be used
  const getLunarInfo = (date: Date) => {
    return {
      hour: "Đinh Hợi",
      day: "Canh Ngọ",
      month: "Mậu Tý",
      year: "Ất Tỵ",
      lunarDay: date.getDate() - 19 > 0 ? date.getDate() - 19 : 30 + (date.getDate() - 19)
    };
  };

  const lunar = getLunarInfo(currentTime);
  const todaySolarStr = currentTime.toISOString().split('T')[0];
  const todayEvents = events.filter(e => e.solarDate === todaySolarStr);
  const upcomingEvents = events
    .filter(e => e.solarDate > todaySolarStr)
    .sort((a, b) => a.solarDate.localeCompare(b.solarDate));

  return (
    <div className="max-w-4xl mx-auto animate-fadeIn space-y-6">
      {/* Decorative Header */}
      <div className="bg-red-900 rounded-t-3xl p-6 relative overflow-hidden">
        <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/oriental-tiles.png')]"></div>
        <div className="flex justify-between items-center relative z-10">
          <h2 className="text-4xl font-traditional text-white font-bold m-0">Sự kiện</h2>
          {isAdmin && (
            <button 
              onClick={() => {
                const title = prompt("Tên sự kiện:");
                const date = prompt("Ngày (YYYY-MM-DD):", todaySolarStr);
                if (title && date) {
                  onAddEvent({
                    id: Date.now().toString(),
                    title,
                    solarDate: date,
                    type: 'họp mặt'
                  });
                }
              }}
              className="bg-white/20 backdrop-blur-md text-white border border-white/30 px-6 py-2 rounded-full font-bold hover:bg-white/40 transition-all flex items-center gap-2"
            >
              <span className="text-xl">+</span> Tạo sự kiện
            </button>
          )}
        </div>
      </div>

      {/* Lunar Dashboard */}
      <div className="bg-[#fffcf0] p-6 rounded-2xl shadow-lg border border-red-900/10 grid grid-cols-4 gap-4 text-center">
        <div className="space-y-1 border-r border-red-900/10">
          <p className="text-gray-600 font-bold text-sm uppercase">Giờ</p>
          <p className="text-3xl font-bold text-red-800">{currentTime.getHours()}:{currentTime.getMinutes().toString().padStart(2, '0')}</p>
          <p className="text-sm text-gray-500 font-medium">{lunar.hour}</p>
        </div>
        <div className="space-y-1 border-r border-red-900/10">
          <p className="text-gray-600 font-bold text-sm uppercase">Ngày</p>
          <p className="text-3xl font-bold text-red-800">{currentTime.getDate()}</p>
          <p className="text-sm text-gray-500 font-medium">{lunar.day}</p>
        </div>
        <div className="space-y-1 border-r border-red-900/10">
          <p className="text-gray-600 font-bold text-sm uppercase">Tháng</p>
          <p className="text-3xl font-bold text-red-800">{currentTime.getMonth() + 1}</p>
          <p className="text-sm text-gray-500 font-medium">{lunar.month}</p>
        </div>
        <div className="space-y-1">
          <p className="text-gray-600 font-bold text-sm uppercase">Năm</p>
          <p className="text-3xl font-bold text-red-800">{currentTime.getFullYear()}</p>
          <p className="text-sm text-gray-500 font-medium">{lunar.year}</p>
        </div>
      </div>

      {/* Calendar View */}
      <div className="bg-[#fffcf0] p-8 rounded-2xl shadow-lg border border-red-900/10">
        <div className="flex justify-between items-center mb-8">
          <button className="text-red-900 text-xl font-bold">❮</button>
