            <h3 className="text-2xl font-bold text-gray-800">Tháng {currentTime.getMonth() + 1} / {currentTime.getFullYear()}</h3>
            <span className="bg-white px-4 py-1 rounded-full border border-gray-200 text-xs font-bold text-gray-500 shadow-sm">2 tuần</span>
          </div>
          <button className="text-red-900 text-xl font-bold">❯</button>
        </div>

        <div className="grid grid-cols-7 gap-2">
          {['CN', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7'].map(d => (
            <div key={d} className="text-center text-xs font-black text-gray-400 mb-4">{d}</div>
          ))}
          {/* Mock Calendar Row (Simulating the 21-27 range in the image) */}
          {[21, 22, 23, 24, 25, 26, 27].map((d, i) => (
            <div 
              key={d} 
              className={`flex flex-col items-center justify-center p-4 rounded-xl transition-all cursor-pointer
                ${d === currentTime.getDate() ? 'bg-gold shadow-lg transform scale-105' : 'hover:bg-red-50'}
