            {todayEvents.length > 0 ? (
              todayEvents.map(e => (
                <div key={e.id} className="flex justify-between items-center py-2">
                  <span className="font-bold text-red-800">{e.title}</span>
                  {isAdmin && <button onClick={() => onDeleteEvent(e.id)} className="text-xs text-red-400">Xóa</button>}
