              <p className="text-gray-400 font-medium italic">Không có sự kiện nào diễn ra hôm nay</p>
            )}
          </div>
        </section>

        <section className="space-y-3">
          <h4 className="text-lg font-bold text-red-950">30 ngày tới</h4>
          <div className="space-y-3">
            {upcomingEvents.length > 0 ? (
              upcomingEvents.map(e => (
                <div key={e.id} className="bg-white p-4 rounded-xl border border-red-900/5 flex justify-between items-center shadow-sm group">
                  <div className="flex gap-4 items-center">
                    <div className="bg-red-50 text-red-800 w-12 h-12 rounded-lg flex flex-col items-center justify-center font-bold">
                       <span className="text-xs">{new Date(e.solarDate).getMonth() + 1}</span>
                       <span className="text-lg leading-none">{new Date(e.solarDate).getDate()}</span>
                    </div>
                    <div>
                      <p className="font-bold text-gray-800">{e.title}</p>
                      <p className="text-[10px] text-gray-400 uppercase tracking-widest">{e.type}</p>
                    </div>
                  </div>
                  {isAdmin && (
                    <button onClick={() => onDeleteEvent(e.id)} className="opacity-0 group-hover:opacity-100 bg-red-50 text-red-600 p-2 rounded-lg transition-opacity hover:bg-red-100">
