              ))
            ) : (
              <div className="bg-white p-8 rounded-2xl border border-dashed border-gray-200 text-center text-gray-400">
                 Chưa có sự kiện sắp tới
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

