    return localStorage.getItem('clan_banner') || "https://images.unsplash.com/photo-1577908581023-95245842c8d2?auto=format&fit=crop&q=80&w=2000";
  });
  const [address, setAddress] = useState<string>(() => {
    return localStorage.getItem('clan_address') || CLAN_ADDRESS;
  });
  const [historyText, setHistoryText] = useState<string>(() => {
    return localStorage.getItem('clan_history') || "Lịch sử dòng họ Lê là một hành trình dài của sự hiếu học, đoàn kết và cống hiến. Khởi nguồn từ vùng đất linh thiêng, con cháu họ Lê đã không ngừng nỗ lực, đóng góp công sức vào sự nghiệp xây dựng và bảo vệ tổ quốc qua nhiều thế hệ.";
  });
  const [ancestralHouseText, setAncestralHouseText] = useState<string>(() => {
    return localStorage.getItem('clan_house_text') || "Từ đường là nơi thờ tự linh thiêng, nơi lưu giữ hồn cốt của tổ tiên qua bao thế hệ. Ngôi từ đường được xây dựng trang nghiêm với kiến trúc truyền thống, là điểm tựa tâm linh và nơi hội tụ của con cháu mỗi dịp Tết đến xuân về.";
  });
  const [regulations, setRegulations] = useState<string[]>(() => {
    const saved = localStorage.getItem('clan_regulations');
    return saved ? JSON.parse(saved) : [
      "Tôn thờ tổ tiên, hiếu thảo với cha mẹ, giữ gìn đạo đức lối sống lành mạnh.",
      "Đoàn kết, tương trợ giữa các thành viên trong dòng họ, giúp đỡ nhau lúc khó khăn.",
      "Khuyến khích và hỗ trợ việc học tập, thành tài của con cháu thế hệ trẻ.",
      "Giữ gìn và tôn tạo các di sản, từ đường và phần mộ của tổ tiên.",
      "Tổ chức trang trọng các ngày lễ giỗ, Tết và đại hội dòng họ hàng năm."
    ];
  });

  // Admin States
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [password, setPassword] = useState('');
  const [editingMember, setEditingMember] = useState<FamilyMember | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState<string | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);
  const [isEditingText, setIsEditingText] = useState(false);

  // Toast Helper
  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  // Sync with LocalStorage
  useEffect(() => { localStorage.setItem('clan_news', JSON.stringify(news)); }, [news]);
  useEffect(() => { localStorage.setItem('clan_tree', JSON.stringify(familyTree)); }, [familyTree]);
  useEffect(() => { localStorage.setItem('clan_events', JSON.stringify(events)); }, [events]);
  useEffect(() => { localStorage.setItem('clan_banner', bannerUrl); }, [bannerUrl]);
  useEffect(() => { localStorage.setItem('clan_address', address); }, [address]);
  useEffect(() => { localStorage.setItem('clan_history', historyText); }, [historyText]);
  useEffect(() => { localStorage.setItem('clan_house_text', ancestralHouseText); }, [ancestralHouseText]);
  useEffect(() => { localStorage.setItem('clan_regulations', JSON.stringify(regulations)); }, [regulations]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') {
      setIsAdmin(true);
      setShowLogin(false);
      setPassword('');
      showToast("Đăng nhập thành công!", "success");
    } else {
      showToast("Mật khẩu không chính xác!", "error");
    }
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setIsEditingText(false);
    setEditingMember(null);
    setEditingNews(null);
    setShowLogin(false);
    showToast("Đã thoát chế độ quản trị", "info");
  };

  const exportAllData = () => {
    const fullData = {
      news,
      familyTree,
      events,
      bannerUrl,
      address,
      historyText,
      ancestralHouseText,
      regulations,
      exportDate: new Date().toISOString(),
      clanName: CLAN_NAME
    };
    const blob = new Blob([JSON.stringify(fullData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `giapha-le-full-backup-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
    showToast("Đã xuất file lưu trữ dữ liệu!", "success");
  };

  const importAllData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.familyTree) setFamilyTree(data.familyTree);
        if (data.news) setNews(data.news);
        if (data.events) setEvents(data.events);
        if (data.bannerUrl) setBannerUrl(data.bannerUrl);
        if (data.address) setAddress(data.address);
        if (data.historyText) setHistoryText(data.historyText);
        if (data.ancestralHouseText) setAncestralHouseText(data.ancestralHouseText);
        if (data.regulations) setRegulations(data.regulations);
        showToast("Đã nhập dữ liệu thành công!", "success");
      } catch (err) {
        showToast("File không hợp lệ!", "error");
      }
    };
    reader.readAsText(file);
  };

  const handleBannerUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        showToast("Kích thước ảnh quá lớn (tối đa 5MB)", "error");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setBannerUrl(reader.result as string);
        showToast("Đã cập nhật ảnh bìa", "success");
      };
      reader.readAsDataURL(file);
    }
  };

  const saveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingMember) return;
    const updateNode = (node: FamilyMember): FamilyMember => {
      if (node.id === editingMember.id) return editingMember;
      if (node.children) {
        return { ...node, children: node.children.map(updateNode) };
      }
      return node;
    };
    setFamilyTree(updateNode(familyTree));
    setEditingMember(null);
    showToast("Đã cập nhật thành viên", "success");
  };

  const saveNews = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingNews) return;
    setNews(prev => {
      const exists = prev.find(n => n.id === editingNews.id);
      if (exists) return prev.map(n => n.id === editingNews.id ? editingNews : n);
      return [editingNews, ...prev];
    });
    setEditingNews(null);
    showToast("Đã lưu tin tức", "success");
  };

  const addChild = (parent: FamilyMember) => {
    const newId = `child-${Date.now()}`;
    const newChild: FamilyMember = {
      id: newId,
      name: 'Thành viên mới',
      generation: parent.generation + 1,
      isMale: true,
      spouseName: '',
      parentName: parent.name
    };
    const addNode = (node: FamilyMember): FamilyMember => {
      if (node.id === parent.id) return { ...node, children: [...(node.children || []), newChild] };
      if (node.children) return { ...node, children: node.children.map(addNode) };
      return node;
    };
    setFamilyTree(addNode(familyTree));
    setEditingMember(newChild);
    showToast("Đã thêm thành viên mới", "success");
  };

  const deleteMember = (id: string) => {
    if (id === familyTree.id) {
      showToast("Không thể xóa Cụ Tổ!", "error");
      return;
    }
    const deleteFromNode = (node: FamilyMember): FamilyMember => {
      if (!node.children) return node;
      return { ...node, children: node.children.filter(child => child.id !== id).map(deleteFromNode) };
    };
    setFamilyTree(deleteFromNode(familyTree));
    setEditingMember(null);
    setShowDeleteConfirm(null);
    showToast("Đã xóa thành viên", "info");
  };

  const renderSection = () => {
    switch (activeSection) {
      case AppSection.NEWS:
        return (
          <div className="animate-fadeIn space-y-8">
            <div className="text-center">
              <h2 className="text-4xl font-traditional text-red-800 font-bold mb-2">Tin Tức Dòng Họ</h2>
              <div className="h-1 w-24 bg-gold mx-auto rounded-full"></div>
            </div>
            {isAdmin && (
              <div className="flex justify-center">
                <button onClick={() => setEditingNews({ id: Date.now().toString(), title: '', date: new Date().toLocaleDateString('vi-VN'), summary: '', content: '', imageUrl: 'https://picsum.photos/800/400' })} className="bg-red-700 text-white px-8 py-3 rounded-full font-bold shadow-xl hover:bg-red-800 transition-all flex items-center gap-2 transform hover:scale-105 active:scale-95">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                  Đăng Tin Mới
                </button>
              </div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {news.map((item) => (
                <div key={item.id} className="bg-white rounded-2xl shadow-traditional overflow-hidden border border-red-900/5 relative group hover:shadow-2xl transition-all duration-500">
                  {isAdmin && (
                    <div className="absolute top-4 right-4 flex gap-2 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => setEditingNews(item)} className="bg-yellow-500/90 backdrop-blur-sm text-white p-2 rounded-full shadow-lg hover:bg-yellow-600">Sửa</button>
                      <button onClick={() => { if(window.confirm("Xóa tin này?")) setNews(news.filter(n => n.id !== item.id)); }} className="bg-red-600/90 backdrop-blur-sm text-white p-2 rounded-full shadow-lg hover:bg-red-700">Xóa</button>
                    </div>
                  )}
                  <div className="h-56 overflow-hidden">
                    <img src={item.imageUrl} alt={item.title} className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700" />
                  </div>
                  <div className="p-8">
                    <div className="flex items-center gap-2 mb-3">
                      <span className="bg-red-50 text-red-800 text-[10px] font-black px-2 py-0.5 rounded uppercase tracking-widest">{item.date}</span>
                    </div>
                    <h3 className="text-2xl font-traditional font-bold text-red-950 mb-4 line-clamp-2 leading-tight">{item.title}</h3>
                    <p className="text-gray-600 text-sm leading-relaxed line-clamp-3 mb-6">{item.summary}</p>
                    <button className="text-red-800 font-bold hover:gap-4 transition-all flex items-center gap-2 group/btn">
                      Đọc tiếp <span className="group-hover/btn:translate-x-1 transition-transform">→</span>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case AppSection.TREE:
        return <FamilyTree root={familyTree} isAdmin={isAdmin} onEditMember={setEditingMember} onAddChild={addChild} />;
      case AppSection.EVENTS:
        return (
          <Events 
            events={events} 
            isAdmin={isAdmin} 
            onAddEvent={(e) => setEvents([...events, e])}
            onDeleteEvent={(id) => setEvents(events.filter(e => e.id !== id))}
          />
        );
      case AppSection.CHRONICLES:
        return (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="bg-white p-12 rounded-3xl shadow-traditional border-[16px] border-double border-red-900/10 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <svg className="w-48 h-48 rotate-12" viewBox="0 0 200 200"><path fill="#8b0000" d="M40,-62C52.6,-54.2,64,-44.1,72.4,-31.6C80.8,-19.1,86.2,-4.2,85.2,10.7C84.2,25.6,76.8,40.4,66.1,51.8C55.4,63.1,41.4,70.9,26.9,76.4C12.4,81.9,-2.6,85.1,-16.7,82.4C-30.8,79.8,-43.9,71.2,-55.1,60.5C-66.3,49.8,-75.6,37,-79.8,22.7C-84,8.4,-83.1,-7.4,-78.3,-21.8C-73.5,-36.2,-64.8,-49.2,-53.1,-57.2C-41.4,-65.2,-26.7,-68.2,-12.3,-70.3C2.1,-72.4,16.4,-73.6,40,-62Z" transform="translate(100 100)" /></svg>
              </div>
              <div className="relative z-10">
                <div className="flex justify-between items-center border-b-2 border-red-900/10 pb-8 mb-10">
                  <h2 className="text-4xl font-traditional text-red-950 italic m-0">Phả Kỹ Dòng Họ Lê</h2>
                  {isAdmin && (
                    <button onClick={() => { if(isEditingText) showToast("Đã lưu Phả Kỹ", "success"); setIsEditingText(!isEditingText); }} className={`px-6 py-2 rounded-full font-bold transition-all ${isEditingText ? 'bg-green-700 text-white shadow-green-900/20' : 'bg-red-800 text-white shadow-red-900/20 hover:bg-red-950'}`}>
                      {isEditingText ? "Hoàn tất" : "Chỉnh sửa"}
                    </button>
                  )}
                </div>
                {isEditingText && isAdmin ? (
                  <textarea value={historyText} onChange={(e) => setHistoryText(e.target.value)} className="w-full h-[500px] p-8 border-2 border-red-100 rounded-2xl bg-red-50/30 font-sans text-lg leading-relaxed focus:border-red-800 outline-none transition-all" />
                ) : (
                  <div className="whitespace-pre-wrap leading-loose text-gray-800 font-medium text-lg text-justify drop-shadow-sm">{historyText}</div>
                )}
                <div className="mt-16 text-center">
                  <span className="text-red-900/20 text-4xl">⚜️ ⚜️ ⚜️</span>
                </div>
              </div>
            </div>
          </div>
        );
      case AppSection.ANCESTRAL_HOUSE:
        return (
          <div className="max-w-5xl mx-auto animate-fadeIn space-y-8">
            <div className="bg-white rounded-[2rem] shadow-traditional border-2 border-red-900/5 overflow-hidden">
              <div className="h-96 relative group">
                <img src="https://images.unsplash.com/photo-1598640845355-668b5550dfb0?auto=format&fit=crop&q=80&w=1600" className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-12">
                   <h2 className="text-5xl font-traditional text-white m-0 drop-shadow-lg">Từ Đường Dòng Họ</h2>
                </div>
              </div>
              <div className="p-12 space-y-10">
                <div className="flex flex-col md:flex-row gap-8 items-start">
                  <div className="flex-1 space-y-6">
                    <div className="flex items-center justify-between">
                      <div className="bg-red-900 text-gold px-6 py-3 rounded-2xl font-bold flex items-center gap-3 shadow-lg">
                        <span className="text-2xl">📍</span>
                        <span className="text-lg">{address}</span>
                      </div>
                      {isAdmin && (
                        <button onClick={() => { const a = prompt('Nhập địa chỉ mới:', address); if(a) setAddress(a); }} className="text-red-800 font-bold underline hover:text-red-950">Đổi địa chỉ</button>
                      )}
                    </div>
                    {isEditingText && isAdmin ? (
                      <textarea value={ancestralHouseText} onChange={(e) => setAncestralHouseText(e.target.value)} className="w-full h-64 p-6 border-2 border-red-100 rounded-2xl bg-red-50/20 focus:border-red-800 outline-none text-gray-700 leading-relaxed text-lg" />
                    ) : (
                      <p className="text-gray-700 leading-loose whitespace-pre-wrap text-xl italic font-medium border-l-8 border-red-900/20 pl-10 py-4">
                        {ancestralHouseText}
                      </p>
                    )}
                    {isAdmin && (
                      <button onClick={() => setIsEditingText(!isEditingText)} className="bg-red-50 text-red-900 px-6 py-2 rounded-full font-bold hover:bg-red-100 transition-all">
                        {isEditingText ? "Lưu mô tả" : "Chỉnh sửa mô tả"}
                      </button>
                    )}
                  </div>
                  <div className="w-full md:w-80 grid grid-cols-2 gap-4">
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">🏮</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Tết Cổ Truyền</span>
                     </div>
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">🍱</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Lễ Chạp Họ</span>
                     </div>
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">🏵️</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Tổ Tiên</span>
                     </div>
                     <div className="h-32 bg-red-50 rounded-2xl flex flex-col items-center justify-center p-4 text-center">
                        <span className="text-3xl mb-2">✉️</span>
                        <span className="text-[10px] font-black uppercase text-red-900/60">Họp Họ</span>
                     </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      case AppSection.REGULATIONS:
        return (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="bg-[#fffcf0] p-16 shadow-2xl rounded-sm border-[20px] border-double border-red-950 relative overflow-hidden">
               {/* Trang trí Tết */}
               <div className="absolute top-0 left-0 w-32 h-32 opacity-10">🌸</div>
               <div className="absolute bottom-0 right-0 w-32 h-32 opacity-10">🌸</div>

               <div className="relative z-10 text-center space-y-12">
                 <div className="space-y-4">
                   <div className="flex items-center justify-center gap-4 text-red-900">
                      <span className="text-3xl">⚜️</span>
                      <h2 className="text-5xl font-traditional m-0 uppercase tracking-[0.2em] font-bold">Tộc Ước</h2>
                      <span className="text-3xl">⚜️</span>
                   </div>
                   <p className="text-red-950 font-traditional italic text-2xl">Gia Tộc Họ Lê</p>
                 </div>

                 {isEditingText && isAdmin ? (
                   <textarea 
                     value={regulations.join('\n')}
                     onChange={(e) => setRegulations(e.target.value.split('\n'))}
                     className="w-full h-[400px] p-10 border-4 border-double border-red-900/20 bg-white/50 font-serif text-xl leading-loose focus:outline-none focus:bg-white transition-all shadow-inner"
                   />
                 ) : (
                   <div className="space-y-10 text-left max-w-2xl mx-auto">
                     {regulations.filter(r => r.trim()).map((reg, idx) => (
                       <div key={idx} className="flex gap-8 group">
                         <div className="flex-shrink-0 w-16 h-16 rounded-full bg-red-900 text-gold flex items-center justify-center font-traditional text-2xl font-bold shadow-lg group-hover:scale-110 transition-transform">
                           {idx + 1}
                         </div>
                         <div className="flex-1 pt-2">
                           <p className="text-xl text-red-950 font-medium italic leading-relaxed">{reg}</p>
                         </div>
                       </div>
                     ))}
                   </div>
                 )}

                 <div className="pt-12 border-t border-red-900/10">
                   <p className="text-red-900 font-traditional italic">"Duy trì gia phong - Gìn giữ cội nguồn"</p>
                   {isAdmin && (
                     <button onClick={() => setIsEditingText(!isEditingText)} className="mt-8 bg-red-950 text-gold px-8 py-3 rounded-full font-bold shadow-xl hover:bg-black transition-all">
                       {isEditingText ? "Lưu thay đổi" : "Biên tập Tộc ước"}
                     </button>
                   )}
                 </div>
               </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-24 selection:bg-red-100 selection:text-red-900">
      {/* Tết Decor: Lồng đèn */}
      <div className="fixed top-0 left-10 z-[100] lantern hidden lg:block">
        <div className="w-1 h-20 bg-red-800 mx-auto"></div>
        <div className="w-16 h-20 bg-red-600 rounded-full border-2 border-gold flex flex-col items-center justify-center shadow-xl">
           <div className="text-gold font-bold text-xs">福</div>
           <div className="w-full h-[2px] bg-gold my-1"></div>
           <div className="text-gold font-bold text-xs">安</div>
        </div>
        <div className="w-10 h-6 bg-red-800 mx-auto rounded-b-lg"></div>
      </div>
      <div className="fixed top-0 right-10 z-[100] lantern hidden lg:block" style={{ animationDelay: '0.5s' }}>
        <div className="w-1 h-16 bg-red-800 mx-auto"></div>
        <div className="w-16 h-20 bg-red-600 rounded-full border-2 border-gold flex flex-col items-center justify-center shadow-xl">
           <div className="text-gold font-bold text-xs">祿</div>
           <div className="w-full h-[2px] bg-gold my-1"></div>
           <div className="text-gold font-bold text-xs">康</div>
        </div>
        <div className="w-10 h-6 bg-red-800 mx-auto rounded-b-lg"></div>
      </div>

      {/* Toast Notification */}
      {toast && (
        <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-3xl shadow-2xl flex items-center gap-4 animate-fadeIn border-2 backdrop-blur-md
          ${toast.type === 'success' ? 'bg-green-900/90 border-green-400 text-white' : 
            toast.type === 'error' ? 'bg-red-950/90 border-red-400 text-white' : 'bg-blue-900/90 border-blue-400 text-white'}`}
        >
          <span className="text-2xl">{toast.type === 'success' ? '✅' : toast.type === 'error' ? '❌' : 'ℹ️'}</span>
          <span className="font-bold tracking-wide">{toast.message}</span>
        </div>
      )}

      {/* Header Banner */}
      <header className="relative w-full h-[400px] md:h-[600px] flex items-center justify-center shadow-2xl overflow-hidden bg-black">
